const book: BibleBook = {
  id: 'nehemiah',
  name: 'Neemias',
  englishName: 'Nehemiah',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'The words of Nehemiah the son of Hacaliah. Now in the month Chislev, in the twentieth year, as I was in Shushan the palace,', pt: 'Palavras de Neemias, filho de Hacalias. Ora, sucedeu no mês de quisleu, no ano vigésimo, estando eu em Susã, a capital,' },
      { v: 2, en: 'Hanani, one of my brothers, came, he and certain men out of Judah; and I asked them about the Jews who had escaped, who were left of the captivity, and concerning Jerusalem.', pt: 'que veio Hanâni, um de meus irmãos, com alguns de Judá; e perguntei-lhes pelos judeus que tinham escapado e que restaram do cativeiro, e acerca de Jerusalém.' },
      { v: 3, en: 'They said to me, “The remnant who are left of the captivity there in the province are in great affliction and reproach. The wall of Jerusalem is also broken down, and its gates are burned with fire.”', pt: 'Eles me responderam: Os restantes que ficaram do cativeiro, lá na província estão em grande aflição e opróbrio; também está derribado o muro de Jerusalém, e as suas portas queimadas a fogo.' },
      { v: 4, en: 'When I heard these words, I sat down and wept, and mourned several days; and I fasted and prayed before the God of heaven,', pt: 'Tendo eu ouvido estas palavras, sentei-me e chorei, e lamentei por alguns dias; e continuei a jejuar e orar perante o Deus do céu,' },
      { v: 5, en: 'and said, “I beg you, Yahweh, the God of heaven, the great and awesome God, who keeps covenant and loving kindness with those who love him and keep his commandments:', pt: 'e disse: Ó Senhor, Deus do céu, Deus grande e temível, que guardas o pacto e usas de misericórdia para com aqueles que te amam e guardam os teus mandamentos:' },
      { v: 6, en: 'Let your ear now be attentive, and your eyes open, that you may listen to the prayer of your servant, which I pray before you at this time, day and night, for the children of Israel your servants, while I confess the sins of the children of Israel, which we have sinned against you. Yes, I and my father’s house have sinned.', pt: 'Estejam atentos os teus ouvidos e abertos os teus olhos, para ouvires a oração do teu servo, que eu hoje faço perante ti, dia e noite, pelos filhos de Israel, teus servos, confessando eu os pecados dos filhos de Israel, que temos cometido contra ti; sim, eu e a casa de meu pai pecamos;' },
      { v: 7, en: 'We have dealt very corruptly against you, and have not kept the commandments, nor the statutes, nor the ordinances, which you commanded your servant Moses.', pt: 'na verdade temos procedido perversamente contra ti, e não temos guardado os mandamentos, nem os estatutos, nem os juízos, que ordenaste a teu servo Moisés.' },
      { v: 8, en: '“Remember, I beg you, the word that you commanded your servant Moses, saying, ‘If you trespass, I will scatter you among the peoples;', pt: 'Lembra-te, pois, da palavra que ordenaste a teu servo Moisés, dizendo: Se vós transgredirdes, eu vos espalharei por entre os povos;' },
      { v: 9, en: 'but if you return to me, and keep my commandments and do them, though your outcasts were in the uttermost part of the heavens, yet I will gather them from there, and will bring them to the place that I have chosen, to cause my name to dwell there.’', pt: 'mas se vos converterdes a mim, e guardardes os meus mandamentos e os cumprirdes, ainda que os vossos rejeitados estejam na extremidade do céu, de lá os ajuntarei e os trarei para o lugar que tenho escolhido para ali fazer habitar o meu nome.' },
      { v: 10, en: '“Now these are your servants and your people, whom you have redeemed by your great power, and by your strong hand.', pt: 'Eles são os teus servos e o teu povo, que resgataste com o teu grande poder e com a tua mão poderosa.' },
      { v: 11, en: 'Lord, I beg you, let your ear be attentive now to the prayer of your servant, and to the prayer of your servants, who delight to fear your name; and please prosper your servant today, and grant him mercy in the sight of this man.” Now I was cup bearer to the king.', pt: 'Ó Senhor, que estejam atentos os teus ouvidos à oração do teu servo, e à oração dos teus servos que se deleitam em temer o teu nome; e faze prosperar hoje o teu servo, e dá-lhe graça perante este homem. (Era eu então copeiro do rei.)' },
    ],
    2: [
      { v: 1, en: 'In the month Nisan, in the twentieth year of Artaxerxes the king, when wine was before him, I picked up the wine, and gave it to the king. Now I had not been sad before in his presence.', pt: 'Sucedeu, pois, no mês de nisã, no ano vigésimos do rei Artaxerxes, quando o vinho estava posto diante dele, que eu apanhei o vinho e o dei ao rei. Ora, eu nunca estivera triste na sua presença.' },
      { v: 2, en: 'The king said to me, “Why is your face sad, since you are not sick? This is nothing else but sorrow of heart.” Then I was very much afraid.', pt: 'E o rei me disse: Por que está triste o teu rosto, visto que não estás doente? Não é isto senão tristeza de coração. Então temi sobremaneira.' },
      { v: 3, en: 'I said to the king, “Let the king live forever! Why shouldn’t my face be sad, when the city, the place of my fathers’ tombs, lies waste, and its gates have been consumed with fire?”', pt: 'e disse ao rei: Viva o rei para sempre! Como não há de estar triste o meu rosto, estando na cidade, o lugar dos sepulcros de meus pais, assolada, e tendo sido consumidas as suas portas pelo fogo?' },
      { v: 4, en: 'Then the king said to me, “What is your request?” So I prayed to the God of heaven.', pt: 'Então o rei me perguntou: Que me pedes agora? Orei, pois, ao Deus do céu,' },
      { v: 5, en: 'I said to the king, “If it pleases the king, and if your servant has found favor in your sight, that you would send me to Judah, to the city of my fathers’ tombs, that I may build it.”', pt: 'e disse ao rei: Se for do agrado do rei, e se teu servo tiver achado graça diante de ti, peço-te que me envies a Judá, à cidade dos sepulcros de meus pais, para que eu a reedifique.' },
      { v: 6, en: 'The king said to me (the queen was also sitting by him), “How long will your journey be? When will you return?” So it pleased the king to send me, and I set a time for him.', pt: 'Então o rei, estando a rainha assentada junto a ele, me disse: Quanto durará a tua viagem, e quando voltarás? E aprouve ao rei enviar-me, apontando-lhe eu certo prazo.' },
      { v: 7, en: 'Moreover I said to the king, “If it pleases the king, let letters be given me to the governors beyond the River, that they may let me pass through until I come to Judah;', pt: 'Eu disse ainda ao rei: Se for do agrado do rei, dêem-se-me cartas para os governadores dalém do Rio, para que me permitam passar até que eu chegue a Judá;' },
      { v: 8, en: 'and a letter to Asaph the keeper of the king’s forest, that he may give me timber to make beams for the gates of the citadel by the temple, for the wall of the city, and for the house that I will occupy.” The king granted my requests, because of the good hand of my God on me.', pt: 'como também uma carta para Asafe, guarda da floresta do rei, a fim de que me dê madeira para as vigas das portas do castelo que pertence à casa, e para o muro da cidade, e para a casa que eu houver de ocupar. E o rei mas deu, graças à mão benéfica do meu Deus sobre mim.' },
      { v: 9, en: 'Then I came to the governors beyond the River, and gave them the king’s letters. Now the king had sent captains of the army and horsemen with me.', pt: 'Então fui ter com os governadores dalém do Rio, e lhes entreguei as cartas do rei. Ora, o rei tinha enviado comigo oficiais do exército e cavaleiros.' },
      { v: 10, en: 'When Sanballat the Horonite, and Tobiah the servant, the Ammonite, heard of it, it grieved them exceedingly, because a man had come to seek the welfare of the children of Israel.', pt: 'O que ouvindo Sambalate, o horonita, e Tobias, o servo amonita, ficaram extremamente agastados de que alguém viesse a procurar o bem dos filhos de Israel.' },
      { v: 11, en: 'So I came to Jerusalem, and was there three days.', pt: 'Cheguei, pois, a Jerusalém, e estive ali três dias.' },
      { v: 12, en: 'I arose in the night, I and a few men with me. I didn’t tell anyone what my God put into my heart to do for Jerusalem. There wasn’t any animal with me, except the animal that I rode on.', pt: 'Então de noite me levantei, eu e uns poucos homens comigo; e não declarei a ninguém o que o meu deus pusera no coração para fazer por Jerusalém. Não havia comigo animal algum, senão aquele que eu montava.' },
      { v: 13, en: 'I went out by night by the valley gate, even toward the jackal’s well, then to the dung gate, and inspected the walls of Jerusalem, which were broken down, and its gates were consumed with fire.', pt: 'Assim saí de noite pela porta do vale, até a fonte do dragão, e até a porta do monturo, e contemplei os muros de Jerusalém, que estavam demolidos, e as suas portas, que tinham sido consumidas pelo fogo.' },
      { v: 14, en: 'Then I went on to the spring gate and to the king’s pool, but there was no place for the animal that was under me to pass.', pt: 'E passei adiante até a porta da fonte, e à piscina do rei; porém não havia lugar por onde pudesse passar o animal que eu montava.' },
      { v: 15, en: 'Then went I up in the night by the brook, and inspected the wall; and I turned back, and entered by the valley gate, and so returned.', pt: 'Ainda de noite subi pelo ribeiro, e contemplei o muro; e virando, entrei pela porta do vale, e assim voltei.' },
      { v: 16, en: 'The rulers didn’t know where I went, or what I did. I had not as yet told it to the Jews, nor to the priests, nor to the nobles, nor to the rulers, nor to the rest who did the work.', pt: 'E não souberam os magistrados aonde eu fora nem o que eu fazia; pois até então eu não havia declarado coisa alguma, nem aos judeus, nem aos sacerdotes, nem aos nobres, nem aos magistrados, nem aos demais que faziam a obra.' },
      { v: 17, en: 'Then I said to them, “You see the bad situation that we are in, how Jerusalem lies waste, and its gates are burned with fire. Come, let us build up the wall of Jerusalem, that we won’t be disgraced.”', pt: 'Então eu lhes disse: Bem vedes vós o triste estado em que estamos, como Jerusalém está assolada, e as suas portas queimadas a fogo; vinde, pois, e edifiquemos o muro de Jerusalém, para que não estejamos mais em opróbrio.' },
      { v: 18, en: 'I told them of the hand of my God which was good on me, as also of the king’s words that he had spoken to me. They said, “Let’s rise up and build.” So they strengthened their hands for the good work.', pt: 'Então lhes declarei como a mão do meu Deus me fora favorável, e bem assim as palavras que o rei me tinha dito. Eles disseram: Levantemo-nos, e edifiquemos. E fortaleceram as mãos para a boa obra.' },
      { v: 19, en: 'But when Sanballat the Horonite, Tobiah the Ammontite servant, and Geshem the Arabian, heard it, they ridiculed us, and despised us, and said, “What is this thing that you are doing? Will you rebel against the king?”', pt: 'O que ouvindo Sambalate, o horonita, e Tobias, o servo amonita, e Gesem, o arábio, zombaram de nós, desprezaram-nos e disseram: O que é isso que fazeis? Quereis rebelar-vos contra o rei?' },
      { v: 20, en: 'Then I answered them, and said to them, “The God of heaven will prosper us. Therefore we, his servants, will arise and build; but you have no portion, nor right, nor memorial, in Jerusalem.”', pt: 'Então lhes respondi: O Deus do céu é que nos fará prosperar; e nós, seus servos, nos levantaremos e edificaremos: mas vós não tendes parte, nem direito, nem memorial em Jerusalém.' },
    ],
    3: [
      { v: 1, en: 'Then Eliashib the high priest rose up with his brothers the priests, and they built the sheep gate. They sanctified it, and set up its doors. They sanctified it even to the tower of Hammeah, to the tower of Hananel.', pt: 'Então se levantou Eliasibe, o sumo sacerdote, juntamente com os seus irmãos, os sacerdotes, e edificaram a porta das ovelhas, a qual consagraram, e lhe assentaram os batentes. Consagraram-na até a torre dos cem, até a torre de Henanel.' },
      { v: 2, en: 'Next to him the men of Jericho built. Next to them Zaccur the son of Imri built.', pt: 'E junto a ele edificaram os homens de Jericó; também ao lado destes edificou Zacur, o filho de Inri.' },
      { v: 3, en: 'The sons of Hassenaah built the fish gate. They laid its beams, and set up its doors, its bolts, and its bars.', pt: 'Os filhos de Hassenaá edificaram a porta dos peixes, colocaram-lhe as vigas, e lhe assentaram os batentes, com seus ferrolhos e trancas.' },
      { v: 4, en: 'Next to them, Meremoth the son of Uriah, the son of Hakkoz made repairs. Next to them, Meshullam the son of Berechiah, the son of Meshezabel made repairs. Next to them, Zadok the son of Baana made repairs.', pt: 'Ao seu lado fez os reparos Meremote, filho de Urias, filho de Hacoz; ao seu lado Mesulão, filho de Berequias, filho de Mesezabel; ao seu lado Zadoque, filho de Baaná;' },
      { v: 5, en: 'Next to them, the Tekoites made repairs; but their nobles didn’t put their necks to the Lord’s work.', pt: 'ao lado destes repararam os tecoítas; porém os seus nobres não meteram o pescoço os serviço do Senhor.' },
      { v: 6, en: 'Joiada the son of Paseah and Meshullam the son of Besodeiah repaired the old gate. They laid its beams, and set up its doors, and its bolts, and its bars.', pt: 'Joiada, filho de Paséia, e Mesulão, filho de Besodéias, repararam a porta velha, colocaram-lhe as vigas, e lhe assentaram os batentes com seus ferrolhos e trancas.' },
      { v: 7, en: 'Next to them, Melatiah the Gibeonite, and Jadon the Meronothite, the men of Gibeon and of Mizpah, repaired the residence of the governor beyond the River.', pt: 'Junto deles fizeram os reparos Melatias, o gibeonita, e Jadom, o meronotita, homens de Gibeão e de Mizpá, que pertenciam ao domínio do governador dalém do Rio;' },
      { v: 8, en: 'Next to him, Uzziel the son of Harhaiah, goldsmiths, made repairs. Next to him, Hananiah, one of the perfumers, made repairs, and they fortified Jerusalem even to the wide wall.', pt: 'ao seu lado Uziel, filho de Haraías, um dos ourives; ao lado dele Hananias, um dos perfumistas; e fortificaram Jerusalém até o muro largo.' },
      { v: 9, en: 'Next to them, Rephaiah the son of Hur, the ruler of half the district of Jerusalem, made repairs.', pt: 'Ao seu lado fez os reparos Refaías, filho de Hur, governador da metade do distrito de Jerusalém;' },
      { v: 10, en: 'Next to them, Jedaiah the son of Harumaph made repairs across from his house. Next to him, Hattush the son of Hashabneiah made repairs.', pt: 'ao seu lado Jedaías, filho de Harumafe, defronte de sua casa; ao seu lado Hatus, filho de Hasabnéias.' },
      { v: 11, en: 'Malchijah the son of Harim, and Hasshub the son of Pahathmoab, repaired another portion, and the tower of the furnaces.', pt: 'Malquias, filho de Harim, e Hassube, filho de Paate-Moabe, repararam outra parte, como também a torre dos fornos;' },
      { v: 12, en: 'Next to him, Shallum the son of Hallohesh, the ruler of half the district of Jerusalem, he and his daughters, made repairs.', pt: 'e ao seu lado Salum, filho de Haloés, governador da outra metade do distrito de Jerusalém, ele e as suas filhas.' },
      { v: 13, en: 'Hanun and the inhabitants of Zanoah repaired the valley gate. They built it, and set up its doors, its bolts, and its bars, and one thousand cubits of the wall to the dung gate.', pt: 'A porta do vale, repararam-na Hanum e os moradores de Zanoa; estes a edificaram, e lhe assentaram os batentes, com seus ferrolhos e trancas, como também mil côvados de muro até a porto do monturo.' },
      { v: 14, en: 'Malchijah the son of Rechab, the ruler of the district of Beth Haccherem repaired the dung gate. He built it, and set up its doors, its bolts, and its bars.', pt: 'A porta do monturo, reparou-a Malquias, filho de Recabe, governador do distrito Bete-Haquerem; este a edificou, e lhe assentou os batentes com seus ferrolhos e trancas.' },
      { v: 15, en: 'Shallun the son of Colhozeh, the ruler of the district of Mizpah repaired the spring gate. He built it, and covered it, and set up its doors, its bolts, and its bars, and the wall of the pool of Shelah by the king’s garden, even to the stairs that go down from David’s city.', pt: 'A porta da fonte, reparou-a Salum, filho de Col-Hoze, governador do distrito de Mizpá; edificou-a e a cobriu, e lhe assentou os batentes, com seus ferrolhos e trancas; edificou também o muro da piscina de Selá, do jardim do rei, até os degraus que descem da cidade de Davi.' },
      { v: 16, en: 'After him, Nehemiah the son of Azbuk, the ruler of half the district of Beth Zur, made repairs to the place opposite the tombs of David, and to the pool that was made, and to the house of the mighty men.', pt: 'Depois dele Neemias, filho de Azbuque, governador da metade do distrito de Bete-Zur, fez os reparos até defronte dos sepulcros de Davi, até a piscina artificial, e até a casa dos homens poderosos.' },
      { v: 17, en: 'After him, the Levites, Rehum the son of Bani made repairs. Next to him, Hashabiah, the ruler of half the district of Keilah, made repairs for his district.', pt: 'Depois dele fizeram os reparos os levitas: Reum, filho de Bani, e ao seu lado, Hasabias, governador da metade do distrito de Queila, por seu distrito;' },
      { v: 18, en: 'After him, their brothers, Bavvai the son of Henadad, the ruler of half the district of Keilah made repairs.', pt: 'depois dele seus irmãos, Bavai, filho de Henadade, governador da outra metade do distrito de Queila.' },
      { v: 19, en: 'Next to him, Ezer the son of Jeshua, the ruler of Mizpah, repaired another portion, across from the ascent to the armory at the turning of the wall.', pt: 'Ao seu lado Ézer, filho de Jesuá, governador de Mizpá, reparou outra parte, defronte da subida para a casa das armas, no ângulo.' },
      { v: 20, en: 'After him, Baruch the son of Zabbai earnestly repaired another portion, from the turning of the wall to the door of the house of Eliashib the high priest.', pt: 'Depois dele reparou Baruque, filho de Zabai, outra parte, desde o ângulo até a porta da casa de Eliasibe, o sumo sacerdote.' },
      { v: 21, en: 'After him, Meremoth the son of Uriah the son of Hakkoz repaired another portion, from the door of the house of Eliashib even to the end of the house of Eliashib.', pt: 'Depois dele reparou Meremote, filho de Urias, filho de Hacoz, outra parte, deste a porta da casa de Eliasibe até a extremidade da mesma.' },
      { v: 22, en: 'After him, the priests, the men of the Plain made repairs.', pt: 'Depois dele fizeram os reparos os sacerdotes que habitavam na campina;' },
      { v: 23, en: 'After them, Benjamin and Hasshub made repairs across from their house. After them, Azariah the son of Maaseiah the son of Ananiah made repairs beside his own house.', pt: 'depois Benjamim e Hassube, defronte da sua casa; depois deles Azarias, filho de Maaséias, filho de Ananias, junto à sua casa.' },
      { v: 24, en: 'After him, Binnui the son of Henadad repaired another portion, from the house of Azariah to the turning of the wall, and to the corner.', pt: 'Depois dele reparou Binuí, filho de Henadade, outra porte, desde a casa de Azarias até o ângulo e até a esquina.' },
      { v: 25, en: 'Palal the son of Uzai made repairs opposite the turning of the wall, and the tower that stands out from the upper house of the king, which is by the court of the guard. After him Pedaiah the son of Parosh made repairs.', pt: 'Palal, filho de Uzai, reparou defronte do ângulo, e a torre que se projeta da casa real superior, que está junto ao átrio da guarda; depois dele Pedaías, filho de Parós.' },
      { v: 26, en: '(Now the temple servants lived in Ophel, to the place over against the water gate toward the east, and the tower that stands out.)', pt: '(Ora, os netinins habitavam em Ofel, até defronte da porta das águas, para o oriente, e até a torre que se projeta.)' },
      { v: 27, en: 'After him the Tekoites repaired another portion, over against the great tower that stands out, and to the wall of Ophel.', pt: 'Depois repararam os tecoítas outra parte, defronte da grande torre que se projeta, e até o muro de Ofel.' },
      { v: 28, en: 'Above the horse gate, the priests made repairs, everyone across from his own house.', pt: 'Para cima da porta dos cavalos fizeram os reparos os sacerdotes, cada um defronte da sua casa;' },
      { v: 29, en: 'After them, Zadok the son of Immer made repairs across from his own house. After him, Shemaiah the son of Shecaniah, the keeper of the east gate made repairs.', pt: 'depois dele Zadoque, filho de Imer, defronte de sua casa; e depois dele Semaías, filho de Secanias, guarda da porta oriental.' },
      { v: 30, en: 'After him, Hananiah the son of Shelemiah, and Hanun the sixth son of Zalaph, repaired another portion. After him, Meshullam the son of Berechiah made repairs across from his room.', pt: 'Depois dele repararam outra parte Hananias, filho de Selemias, e Hanum, o sexto filho de Zalafe. Depois dele reparou Mesulão, filho de Berequias, uma parte defronte da sua câmara.' },
      { v: 31, en: 'After him, Malchijah, one of the goldsmiths to the house of the temple servants, and of the merchants, made repairs opposite the gate of Hammiphkad, and to the ascent of the corner.', pt: 'Depois dele reparou Malquias, um dos ourives, uma parte até a casa dos netinins e dos mercadores, defronte da porta da guarda, e até a câmara superior da esquina.' },
      { v: 32, en: 'Between the ascent of the corner and the sheep gate, the goldsmiths and the merchants made repairs.', pt: 'E entre a câmara da esquina e a porta das ovelhas repararam os ourives e os mercadores.' },
    ],
    4: [
      { v: 1, en: 'But when Sanballat heard that we were building the wall, he was angry, and was very indignant, and mocked the Jews.', pt: 'Ora, quando Sambalate ouviu que edificávamos o muro, ardeu em ira,indignou-se muito e escarneceu dos judeus;' },
      { v: 2, en: 'He spoke before his brothers and the army of Samaria, and said, “What are these feeble Jews doing? Will they fortify themselves? Will they sacrifice? Will they finish in a day? Will they revive the stones out of the heaps of rubbish, since they are burned?”', pt: 'e falou na presença de seus irmãos e do exército de Samária, dizendo: Que fazem estes fracos judeus? Fortificar-se-ão? Oferecerão sacrifícios? Acabarão a obra num só dia? Vivificarão dos montões de pó as pedras que foram queimadas?' },
      { v: 3, en: 'Now Tobiah the Ammonite was by him, and he said, “What they are building, if a fox climbed up it, he would break down their stone wall.”', pt: 'Ora, estava ao lado dele Tobias, o amonita, que disse: Ainda que edifiquem,vindo uma raposa derrubará o seu muro de pedra.' },
      { v: 4, en: '“Hear, our God; for we are despised; and turn back their reproach on their own head, give them up for a plunder in a land of captivity;', pt: 'Ouve, ó nosso Deus, pois somos tão desprezados; faze recair o opróbrio deles sobre as suas cabaças, e faze com que eles sejam um despojo numa terra de cativeiro.' },
      { v: 5, en: 'don’t cover their iniquity, and don’t let their sin be blotted out from before you; for they have insulted the builders.”', pt: 'Não cubras a sua iniquidade, e não se risque de diante de ti o seu pecado, pois que te provocaram à ira na presença dos edificadores.' },
      { v: 6, en: 'So we built the wall; and all the wall was joined together to half its height: for the people had a mind to work.', pt: 'Assim edificamos o muro; e todo o muro se completou até a metade da sua altura; porque o coração do povo se inclinava a trabalhar.' },
      { v: 7, en: 'But when Sanballat, Tobiah, the Arabians, the Ammonites, and the Ashdodites heard that the repairing of the walls of Jerusalem went forward, and that the breaches began to be filled, they were very angry;', pt: 'Mas, ouvindo Sambalate e Tobias, e os arábios, o amonitas e os asdoditas, que ia avante a reparação dos muros de Jerusalém e que já as brechas se começavam a fechar, iraram-se sobremodo;' },
      { v: 8, en: 'and they all conspired together to come and fight against Jerusalem, and to cause confusion among us.', pt: 'e coligaram-se todos, para virem guerrear contra Jerusalém e fazer confusão' },
      { v: 9, en: 'But we made our prayer to our God, and set a watch against them day and night, because of them.', pt: 'Nós, porém, oramos ao nosso Deus, e pusemos guarda contra eles de dia e de noite.' },
      { v: 10, en: 'Judah said, “The strength of the bearers of burdens is fading, and there is much rubble; so that we are not able to build the wall.”', pt: 'Então disse Judá: Desfalecem as forças dos carregadores, e há muito escombro; não poderemos edificar o muro.' },
      { v: 11, en: 'Our adversaries said, “They will not know or see, until we come in among them and kill them, and cause the work to cease.”', pt: 'E os nossos inimigos disseram: Nada saberão nem verão, até que entremos no meio deles, e os matemos, e façamos cessar a obra.' },
      { v: 12, en: 'When the Jews who lived by them came, they said to us ten times from all places, “Wherever you turn, they will attack us.”', pt: 'Mas sucedeu que, vindo os judeus que habitavam entre eles, dez vezes nos disseram: De todos os lugares de onde moram subirão contra nós.' },
      { v: 13, en: 'Therefore I set guards in the lowest parts of the space behind the wall, in the open places. I set the people by family groups with their swords, their spears, and their bows.', pt: 'Pelo que nos lugares baixos por detrás do muro e nos lugares abertos, dispus o povo segundo suas famílias com as suas espadas, com as suas lanças, e com os seus arcos.' },
      { v: 14, en: 'I looked, and rose up, and said to the nobles, to the rulers, and to the rest of the people, “Don’t be afraid of them! Remember the Lord, who is great and awesome, and fight for your brothers, your sons, your daughters, your wives, and your houses.”', pt: 'Olhei, levantei-me, e disse aos nobres, aos magistrados e ao resto do povo: Não os temais! Lembrai-vos do Senhor, grande e temível, e pelejai por vossos irmãos, vossos filhos, vossas filhas, vossas mulheres e vossas casas.' },
      { v: 15, en: 'When our enemies heard that it was known to us, and God had brought their counsel to nothing, all of us returned to the wall, everyone to his work.', pt: 'Quando os nossos inimigos souberam que nós tínhamos sido avisados, e que Deus tinha dissipado o conselho deles, todos voltamos ao muro, cada um para a sua obra.' },
      { v: 16, en: 'From that time forth, half of my servants did the work, and half of them held the spears, the shields, the bows, and the coats of mail; and the rulers were behind all the house of Judah.', pt: 'Desde aquele dia metade dos meus moços trabalhavam na obra, e a outra metade empunhava as lanças, os escudos, os arcos, e as couraças; e os chefes estavam por detrás de toda a casa de Judá.' },
      { v: 17, en: 'Those who built the wall, and those who bore burdens loaded themselves; everyone with one of his hands did the work, and with the other held his weapon.', pt: 'Os que estavam edificando o muro, e os carregadores que levavam as cargas, cada um com uma das mãos fazia a obra e com a outra segurava a sua arma;' },
      { v: 18, en: 'Among the builders, everyone wore his sword at his side, and so built. He who sounded the trumpet was by me.', pt: 'e cada um dos edificadores trazia a sua espada à cinta, e assim edificavam. E o que tocava a trombeta estava no meu lado.' },
      { v: 19, en: 'I said to the nobles, and to the rulers and to the rest of the people, “The work is great and large, and we are separated on the wall, far from one another.', pt: 'Disse eu aos nobres, aos magistrados e ao resto do povo: Grande e extensa é a obra, e nós estamos separados no muro, longe uns dos outros;' },
      { v: 20, en: 'Wherever you hear the sound of the trumpet, rally there to us. Our God will fight for us.”', pt: 'em qualquer lugar em que ouvirdes o som da trombeta, ali vos ajuntareis conosco. O nosso Deus pelejará por nós.' },
      { v: 21, en: 'So we did the work. Half of the people held the spears from the rising of the morning until the stars appeared.', pt: 'Assim trabalhávamos na obra; e metade deles empunhava as lanças desde a subida da alva até o sair das estrelas.' },
      { v: 22, en: 'Likewise at the same time said I to the people, “Let everyone with his servant lodge within Jerusalem, that in the night they may be a guard to us, and may labor in the day.”', pt: 'Também nesse tempo eu disse ao povo: Cada um com o seu moço pernoite em Jerusalém, para que de noite nos sirvam de guardas, e de dia trabalhem.' },
      { v: 23, en: 'So neither I, nor my brothers, nor my servants, nor the men of the guard who followed me, none of us took off our clothes. Everyone took his weapon to the water.', pt: 'Desta maneira nem eu, nem meus irmãos, nem meus moços, nem os homens da guarda que me acompanhavam largávamos as nossas vestes; cada um ia com a arma à sua direita.' },
    ],
    5: [
      { v: 1, en: 'Then there arose a great cry of the people and of their wives against their brothers the Jews.', pt: 'Então se levantou um grande clamor do povo e de duas mulheres contra os judeus, seus irmãos.' },
      { v: 2, en: 'For there were that said, “We, our sons and our daughters, are many. Let us get grain, that we may eat and live.”', pt: 'Pois havia alguns que diziam: Nós, nossos filhos e nossas filhas somos muitos; que se nos dê trigo, para que comamos e vivamos.' },
      { v: 3, en: 'There were also some that said, “We are mortgaging our fields, and our vineyards, and our houses. Let us get grain, because of the famine.”', pt: 'Também havia os que diziam: Estamos empenhando nossos campos, as nossas vinhas e as nossas casas, para conseguirmos trigo durante esta fome.' },
      { v: 4, en: 'There were also some who said, “We have borrowed money for the king’s tribute using our fields and our vineyards as collateral.', pt: 'Havia ainda outros que diziam: Temos tomado dinheiro emprestado até para o tributo do rei sobre os nossos campos e as nossas vinhas.' },
      { v: 5, en: 'Yet now our flesh is as the flesh of our brothers, our children as their children. Behold, we bring our sons and our daughters into bondage to be servants, and some of our daughters have been brought into bondage. It is also not in our power to help it, because other men have our fields and our vineyards.”', pt: 'Ora, a nossa carne é como a carne de nossos irmãos, e nossos filhos como os filhos deles; e eis que estamos sujeitando nossos filhos e nossas filhas para serem servos, e algumas de nossas filhas já estão reduzidas à escravidão. Não está em nosso poder evitá-lo, pois outros têm os nossos campos e as nossas vinhas.' },
      { v: 6, en: 'I was very angry when I heard their cry and these words.', pt: 'Ouvindo eu, pois, o seu clamor, e estas palavras, muito me indignei.' },
      { v: 7, en: 'Then I consulted with myself, and contended with the nobles and the rulers, and said to them, “You exact usury, everyone of his brother.” I held a great assembly against them.', pt: 'Então consultei comigo mesmo; depois contendi com do nobres e com os magistrados, e disse-lhes: Estais tomando juros, cada um de seu irmão. E ajuntei contra eles uma grande assembléia.' },
      { v: 8, en: 'I said to them, “We, after our ability, have redeemed our brothers the Jews that were sold to the nations; and would you even sell your brothers, and should they be sold to us?” Then they held their peace, and found not a word to say.', pt: 'E disse-lhes: Nós, segundo as nossas posses, temos resgatado os judeus, nossos irmãos, que foram vendidos às nações; e vós venderíeis os vossos irmãos, ou seriam vendidos a nós? Então se calaram, e não acharam o que responder.' },
      { v: 9, en: 'Also I said, “The thing that you do is not good. Shouldn’t you walk in the fear of our God, because of the reproach of the nations our enemies?', pt: 'Disse mais: Não é bom o que fazeis; porventura não devíeis andar no temor do nosso Deus, por causa do opróbrio dos povos, os nosso inimigos? 10Também eu, meus irmãos e meus moços lhes temos emprestado dinheiro e trigo. Deixemos, peço-vos este ganho.' },
      { v: 10, en: 'I likewise, my brothers and my servants, lend them money and grain. Please let us stop this usury.', pt: 'Restituí-lhes hoje os seus campos, as suas vinhas, os seus olivais e as suas casas, como também a centésima parte do dinheiro, do trigo, do mosto e do azeite, que deles tendes exigido.' },
      { v: 11, en: 'Please restore to them, even today, their fields, their vineyards, their olive groves, and their houses, also the hundredth part of the money, and of the grain, the new wine, and the oil, that you are charging them.”', pt: 'Então disseram: Nós lho restituiremos, e nada lhes pediremos; faremos assim como dizes. Então, chamando os sacerdotes, fi-los jurar que fariam conforme prometeram.' },
      { v: 12, en: 'Then they said, “We will restore them, and will require nothing of them. We will do so, even as you say.” Then I called the priests, and took an oath of them, that they would do according to this promise.', pt: 'Também sacudi as minhas vestes, e disse: Assim sacuda Deus da sua casa e do seu trabalho todo homem que não cumprir esta promessa; assim mesmo seja ele sacudido e despojado. E toda a congregação disse: Amém! E louvaram ao Senhor; e o povo fez conforme a sua promessa.' },
      { v: 13, en: 'Also I shook out my lap, and said, “So may God shake out every man from his house, and from his labor, that doesn’t perform this promise; even be he shaken out, and emptied like this.” All the assembly said, “Amen,” and praised Yahweh. The people did according to this promise.', pt: 'Além disso, desde o dia em que fui nomeado seu governador na terra de Judá, desde o ano vinte até o anos trinta e dois do rei Artaxerxes, isto é, por doze anos, nem eu nem meus irmãos comemos o pão devido ao governador.' },
      { v: 14, en: 'Moreover from the time that I was appointed to be their governor in the land of Judah, from the twentieth year even to the thirty-second year of Artaxerxes the king, that is, twelve years, I and my brothers have not eaten the bread of the governor.', pt: 'Mas os primeiros governadores, que foram antes de mim, oprimiram o povo, e tomaram-lhe pão e vinho e, além disso, quarenta siclos de prata; e até os seus moços dominavam sobre o povo. Porém eu assim não fiz, por causa do temor de Deus.' },
      { v: 15, en: 'But the former governors who were before me were supported by the people, and took bread and wine from them, plus forty shekels of silver; yes, even their servants ruled over the people; but I didn’t do so, because of the fear of God.', pt: 'Também eu prossegui na obra deste muro, e terra nenhuma compramos; e todos os meus moços se ajuntaram ali para a obra.' },
      { v: 16, en: 'Yes, I also continued in the work of this wall. We didn’t buy any land. All my servants were gathered there to the work.', pt: 'Sentavam-se à minha mesa cento e cinqüenta homens dentre os judeus e os magistrados, além dos que vinham ter conosco dentre as nações que estavam ao redor de nós.' },
      { v: 17, en: 'Moreover there were at my table, of the Jews and the rulers, one hundred fifty men, besides those who came to us from among the nations that were around us.', pt: 'Ora, o que se preparava para cada dia era um boi e seis ovelhas escolhidas; também se preparavam aves e, de dez em dez dias, provisão de toda qualidade de vinho. Todavia, nem por isso exigi o pão devido ao governador, porquanto a servidão deste povo era pesada.' },
      { v: 18, en: 'Now that which was prepared for one day was one ox and six choice sheep. Also fowls were prepared for me, and once in ten days a store of all sorts of wine. Yet for all this, I didn’t demand the governor’s pay, because the bondage was heavy on this people.', pt: 'Lembra-te de mim para teu bem, ó meu Deus, e de tudo quanto tenho feito em prol deste povo' },
      { v: 19, en: 'Remember to me, my God, for good, all that I have done for this people.', pt: 'Remember to me, my God, for good, all that I have done for this people.' },
    ],
    6: [
      { v: 1, en: 'Now when it was reported to Sanballat, Tobiah, and to Geshem the Arabian, and to the rest of our enemies, that I had built the wall, and that there was no breach left in it (though even to that time I had not set up the doors in the gates)', pt: 'Quando Sambalate, Tobias e Gesem, o arábio, e o resto dos nossos inimigos souberam que eu já tinha edificado o muro e que nele já não havia brecha alguma, ainda que até este tempo não tinha posto as portas nos portais,' },
      { v: 2, en: 'Sanballat and Geshem sent to me, saying, “Come, let us meet together in the villages in the plain of Ono.” But they intended to harm me.', pt: 'Sambalate e Gesem mandaram dizer-me: Vem, encontremo-nos numa das aldeias da planície de Ono. Eles, porém, intentavam fazer-me mal.' },
      { v: 3, en: 'I sent messengers to them, saying, “I am doing a great work, so that I can’t come down. Why should the work cease, while I leave it, and come down to you?”', pt: 'E enviei-lhes mensageiros a dizer: Estou fazendo uma grande obra, de modo que não poderei descer. Por que cessaria esta obra, enquanto eu a deixasse e fosse ter convosco?' },
      { v: 4, en: 'They sent to me four times like this; and I answered them the same way.', pt: 'Do mesmo modo mandaram dizer-se quatro vezes; e do mesmo modo lhes respondi.' },
      { v: 5, en: 'Then Sanballat sent his servant to me the same way the fifth time with an open letter in his hand,', pt: 'Então Sambalate, ainda pela quinta vez, me enviou o seu moço com uma carta aberta na mão,' },
      { v: 6, en: 'in which was written, “It is reported among the nations, and Gashmu says it, that you and the Jews intend to rebel. Because of that, you are building the wall. You would be their king, according to these words.', pt: 'na qual estava escrito: Entre as nações se ouviu, e Gesem o diz, que tu e os judeus intentais revoltar-vos, e por isso tu estás edificando o muro, e segundo se diz, queres fazer-te rei deles;' },
      { v: 7, en: 'You have also appointed prophets to proclaim of you at Jerusalem, saying, ‘There is a king in Judah!’ Now it will be reported to the king according to these words. Come now therefore, and let us take counsel together.”', pt: 'e que constituíste profetas para proclamarem a respeito de ti em Jerusalém: Há rei em Judá. Ora, estas coisas chegarão aos ouvidos do rei; vem pois, agora e consultemos juntamente.' },
      { v: 8, en: 'Then I sent to him, saying, “There are no such things done as you say, but you imagine them out of your own heart.”', pt: 'Então mandei dizer-lhe: De tudo o que dizes, coisa nenhuma sucedeu, mas tu mesmo o inventas.' },
      { v: 9, en: 'For they all would have made us afraid, saying, “Their hands will be weakened from the work, that it not be done.” But now, strengthen my hands.', pt: 'Pois todos eles nos procuravam atemorizar, dizendo: As suas mãos hão de largar a obra, e não se efetuará. Mas agora, ó Deus, fortalece as minhas mãos.' },
      { v: 10, en: 'I went to the house of Shemaiah the son of Delaiah the son of Mehetabel, who was shut in at his home; and he said, “Let us meet together in God’s house, within the temple, and let us shut the doors of the temple; for they will come to kill you. Yes, in the night will they come to kill you.”', pt: 'Fui à casa de Semaías, filho de Delaías, filho de Meetabel, que estava em recolhimento; e disse ele: Ajuntemo-nos na casa de Deus, dentro do templo, e fechemos as suas portas, pois virão matar-te; sim, de noite virão matar-te.' },
      { v: 11, en: 'I said, “Should a man like me flee? Who is there that, being such as I, would go into the temple to save his life? I will not go in.”', pt: 'Eu, porém, respondi: Um homem como eu fugiria? e quem há que, sendo tal como eu, possa entrar no templo e viver? De maneira nenhuma entrarei.' },
      { v: 12, en: 'I discerned, and behold, God had not sent him; but he pronounced this prophecy against me. Tobiah and Sanballat had hired him.', pt: 'E percebi que não era Deus que o enviara; mas ele pronunciou essa profecia contra mim, porquanto Tobias e Sambalate o haviam subornado.' },
      { v: 13, en: 'He hired so that I would be afraid, do so, and sin, and that they might have material for an evil report, that they might reproach me.', pt: 'Eles o subornaram para me atemorizar, a fim de que eu assim fizesse, e pecasse, para que tivessem de que me infamar, e assim vituperassem.' },
      { v: 14, en: '“Remember, my God, Tobiah and Sanballat according to these their works, and also the prophetess Noadiah, and the rest of the prophets, that would have put me in fear.”', pt: 'Lembra-te, meu Deus, de Tobias e de Sambalate, conforme estas suas obras, e também da profetisa Noadias, e dos demais profetas que procuravam atemorizar-me.' },
      { v: 15, en: 'So the wall was finished in the twenty-fifth day of Elul, in fifty-two days.', pt: 'Acabou-se, pois, o muro aos vinte e cinco do mês de elul, em cinqüenta e dois dias.' },
      { v: 16, en: 'When all our enemies heard of it, all the nations that were around us were afraid, and they lost their confidence; for they perceived that this work was done by our God.', pt: 'Quando todos os nosso inimigos souberam disso, todos os povos que havia em redor de nós temeram, e abateram-se muito em seu próprio conceito; pois perceberam que fizemos esta obra com o auxílio do nosso Deus.' },
      { v: 17, en: 'Moreover in those days the nobles of Judah sent many letters to Tobiah, and Tobiah’s letters came to them.', pt: 'Além disso, naqueles dias o nobres de Judá enviaram muitas cartas a Tobias, e as cartas de Tobias vinham para eles.' },
      { v: 18, en: 'For there were many in Judah sworn to him, because he was the son-in-law of Shecaniah the son of Arah; and his son Jehohanan had taken the daughter of Meshullam the son of Berechiah as wife.', pt: 'Pois muitos em Judá estavam ligados a ele por juramento, por ser ele genro de Secanias, filho de Ará, e por haver seu filho Joanã casado com a filha de Mesulão, filho de Berequias.' },
      { v: 19, en: 'Also they spoke of his good deeds before me, and reported my words to him. Tobiah sent letters to put me in fear.', pt: 'Também as boas ações dele contavam perante mim, e as minhas palavras transmitiam a ele. Tobias, pois, escrevia cartas para me atemorizar.' },
    ],
    7: [
      { v: 1, en: 'Now when the wall was built, and I had set up the doors, and the gatekeepers and the singers and the Levites were appointed,', pt: 'Ora, depois que o muro foi edificado, tendo eu assentado as portas, e havendo sido designados os porteiros, os cantores e os levitas,' },
      { v: 2, en: 'I put my brother Hanani, and Hananiah the governor of the fortress, in charge of Jerusalem; for he was a faithful man, and feared God above many.', pt: 'pus Hanâni, meu irmão, e Hananias, governador do castelo, sobre Jerusalém; pois ele era homem fiel e temente a Deus, mais do que muitos;' },
      { v: 3, en: 'I said to them, “Don’t let the gates of Jerusalem be opened until the sun is hot; and while they stand guard, let them shut the doors, and you bar them: and appoint watches of the inhabitants of Jerusalem, everyone in his watch, with everyone near his house.”', pt: 'e eu lhes disse: Não se abram as portas de Jerusalém até que o sol aqueça; e enquanto os guardas estiverem nos postos se fechem e se tranquem as portas; e designei dentre os moradores de Jerusalém guardas, cada um por seu turno, e cada um diante da sua casa.' },
      { v: 4, en: 'Now the city was wide and large; but the people were few therein, and the houses were not built.', pt: 'Ora, a cidade era larga e grande, mas o povo dentro dela era pouco, e ainda as casa não estavam edificadas.' },
      { v: 5, en: 'My God put into my heart to gather together the nobles, and the rulers, and the people, that they might be listed by genealogy. I found the book of the genealogy of those who came up at the first, and I found this written in it:', pt: 'Então o meu Deus me pôs no coração que ajuntasse os nobres, os magistrados e o povo, para registrar as genealogias. E achei o livro da genealogia dos que tinham subido primeiro e achei escrito nele o seguinte:' },
      { v: 6, en: 'These are the children of the province, who went up out of the captivity of those who had been carried away, whom Nebuchadnezzar the king of Babylon had carried away, and who returned to Jerusalem and to Judah, everyone to his city;', pt: 'Este são os filhos da província que subiram do cativeiro dentre os exilados, que Nabucodonozor, rei da Babilônia, transportara e que voltaram para Jerusalém e para Judá, cada um para a sua cidade,' },
      { v: 7, en: 'who came with Zerubbabel, Jeshua, Nehemiah, Azariah, Raamiah, Nahamani, Mordecai, Bilshan, Mispereth, Bigvai, Nehum, Baanah. The number of the men of the people of Israel:', pt: 'os quais vieram com Zorobabel, Jesuá, Neemias, Azarias, Raamias, Naamâni, Mardoqueu, Bilsã, Misperete, Bigvai, Neum e Baaná. Este é o número dos homens do povo de Israel:' },
      { v: 8, en: 'The children of Parosh, two thousand one hundred seventy-two.', pt: 'foram os filhos de Parós, dois mil cento e setenta e dois;' },
      { v: 9, en: 'The children of Shephatiah, three hundred seventy-two.', pt: 'os filhos de Sefatias, trezentos e setenta e dois;' },
      { v: 10, en: 'The children of Arah, six hundred fifty-two.', pt: 'os filhos de Ará, seiscentos e cinqüenta e dois;' },
      { v: 11, en: 'The children of Pahathmoab, of the children of Jeshua and Joab, two thousand eight hundred eighteen.', pt: 'os filhos de Paate-Moabe, dos filhos de Jesuá e de Joabe, dois mil oitocentos e dezoito;' },
      { v: 12, en: 'The children of Elam, one thousand two hundred fifty-four.', pt: 'os filhos de Elão, mil duzentos e cinqüenta e quatro;' },
      { v: 13, en: 'The children of Zattu, eight hundred forty-five.', pt: 'os filhos de Zatu, oitocentos e quarenta e cinco;' },
      { v: 14, en: 'The children of Zaccai, seven hundred sixty.', pt: 'os filhos de Zacai, setecentos e sessenta;' },
      { v: 15, en: 'The children of Binnui, six hundred forty-eight.', pt: 'os filhos de Binuí, seiscentos e quarenta e oito;' },
      { v: 16, en: 'The children of Bebai, six hundred twenty-eight.', pt: 'os filhos de Bebai, seiscentos e vinte e oito;' },
      { v: 17, en: 'The children of Azgad, two thousand three hundred twenty-two.', pt: 'os filhos de Azgade, dois mil trezentos e vinte e dois;' },
      { v: 18, en: 'The children of Adonikam, six hundred sixty-seven.', pt: 'os filhos de Adonicão, seiscentos e sessenta e sete;' },
      { v: 19, en: 'The children of Bigvai, two thousand sixty-seven.', pt: 'os filhos de Bigvai, dois mil e sessenta e sete;' },
      { v: 20, en: 'The children of Adin, six hundred fifty-five.', pt: 'os filhos de Adim, seiscentos e cinqüenta e cinco;' },
      { v: 21, en: 'The children of Ater, of Hezekiah, ninety-eight.', pt: 'os filhos de Ater, de Ezequias, noventa e oito;' },
      { v: 22, en: 'The children of Hashum, three hundred twenty-eight.', pt: 'os filhos de Hasum, trezentos e vinte e oito;' },
      { v: 23, en: 'The children of Bezai, three hundred twenty-four.', pt: 'os filhos de Bezai, trezentos e vinte e quatro;' },
      { v: 24, en: 'The children of Hariph, one hundred twelve.', pt: 'os filhos de Harife, cento e doze;' },
      { v: 25, en: 'The children of Gibeon, ninety-five.', pt: 'os filhos de Gibeão, noventa e cinco;' },
      { v: 26, en: 'The men of Bethlehem and Netophah, one hundred eighty-eight.', pt: 'os filhos de Belém e de Netofá, cento e oitenta e oito;' },
      { v: 27, en: 'The men of Anathoth, one hundred twenty-eight.', pt: 'os homens de Anatote, cento e vinte e oito;' },
      { v: 28, en: 'The men of Beth Azmaveth, forty-two.', pt: 'os homens de Bete-Azmavete, quarenta e dois;' },
      { v: 29, en: 'The men of Kiriath Jearim, Chephirah, and Beeroth, seven hundred forty-three.', pt: 'os homens de Quiriate-Jeriam, de Cefira, e de Beerote, setecentos e quarenta e três;' },
      { v: 30, en: 'The men of Ramah and Geba, six hundred twenty-one.', pt: 'os homens de Ramá e Gaba, seiscentos e vinte e um;' },
      { v: 31, en: 'The men of Michmas, one hundred twenty-two.', pt: 'os homens de Micmás, cento e vinte e dois;' },
      { v: 32, en: 'The men of Bethel and Ai, one hundred twenty-three.', pt: 'os homens de Betel e Ai, cento e vinte e três;' },
      { v: 33, en: 'The men of the other Nebo, fifty-two.', pt: 'os homens do outro Nebo, cinqüenta e dois;' },
      { v: 34, en: 'The children of the other Elam, one thousand two hundred fifty-four.', pt: 'os filhos do outro Elão, mil duzentos e cinqüenta e quatro;' },
      { v: 35, en: 'The children of Harim, three hundred twenty.', pt: 'os filhos de Harim, trezentos e vinte;' },
      { v: 36, en: 'The children of Jericho, three hundred forty-five.', pt: 'os filhos de Jericó, trezentos e quarenta e cinco;' },
      { v: 37, en: 'The children of Lod, Hadid, and Ono, seven hundred twenty-one.', pt: 'os filhos de Lode, de hadide e de Ono, setecentos e vinte e um;' },
      { v: 38, en: 'The children of Senaah, three thousand nine hundred thirty.', pt: 'os filhos de Senaá, três mil novecentos e trinta.' },
      { v: 39, en: 'The priests: The children of Jedaiah, of the house of Jeshua, nine hundred seventy-three.', pt: 'Os sacerdotes: os filhos de Jedaías, da casa de Jesuá, novecentos e setenta e três;' },
      { v: 40, en: 'The children of Immer, one thousand fifty-two.', pt: 'os filhos de Imer, mil e cinqüenta e dois;' },
      { v: 41, en: 'The children of Pashhur, one thousand two hundred forty-seven.', pt: 'os filhos de Pasur, mil duzentos e quarenta e sete;' },
      { v: 42, en: 'The children of Harim, one thousand seventeen.', pt: 'os filhos de Harim, mil e dezessete;' },
      { v: 43, en: 'The Levites: the children of Jeshua, of Kadmiel, of the children of Hodevah, seventy-four.', pt: 'Os levitas: os filhos de Jesuá, de Cadmiel, dos filhos de Hodevá, setenta e quatro.' },
      { v: 44, en: 'The singers: the children of Asaph, one hundred forty-eight.', pt: 'Os cantores: os filhos de Asafe, cento e quarenta e oito.' },
      { v: 45, en: 'The gatekeepers: the children of Shallum, the children of Ater, the children of Talmon, the children of Akkub, the children of Hatita, the children of Shobai, one hundred thirty-eight.', pt: 'Os porteiros: os filhos de Salum, os filhos de Ater, os filhos de Talmom, os filhos de Acube, os filhos de Hatita, os filhos de Sobai, cento e trinta e oito.' },
      { v: 46, en: 'The temple servants: the children of Ziha, the children of Hasupha, the children of Tabbaoth,', pt: 'Os netinis: os filhos de Ziá, os filhos de Hasufa, os filhos de Tabaote,' },
      { v: 47, en: 'the children of Keros, the children of Sia, the children of Padon,', pt: 'os filhos de Querós, os filhos de Siá, os filhos de Padom,' },
      { v: 48, en: 'the children of Lebana, the children of Hagaba, the children of Salmai,', pt: 'os filhos de Lebana, os filhos de Hagaba, os filhos de Salmai,' },
      { v: 49, en: 'the children of Hanan, the children of Giddel, the children of Gahar,', pt: 'os filhos de Hanã, os filhos de Gidel, os filhos de Gaar,' },
      { v: 50, en: 'the children of Reaiah, the children of Rezin, the children of Nekoda,', pt: 'os filhos de Recaías, os filhos de Rezim, os filhos de Necoda,' },
      { v: 51, en: 'the children of Gazzam, the children of Uzza, the children of Paseah.', pt: 'os filhos de Gazão, os filhos de Uzá, os filhos de Paséia,' },
      { v: 52, en: 'The children of Besai, the children of Meunim, the children of Nephushesim,', pt: 'os filhos de Besai, os filhos de Meunim, os filhos de Nefusesim,' },
      { v: 53, en: 'the children of Bakbuk, the children of Hakupha, the children of Harhur,', pt: 'os filhos de Baquebuque, os filhos de Hacufa, os filhos de Hacur,' },
      { v: 54, en: 'the children of Bazlith, the children of Mehida, the children of Harsha,', pt: 'os filhos de Bazlite, os filhos de Meída, os filhos de Harsa,' },
      { v: 55, en: 'the children of Barkos, the children of Sisera, the children of Temah,', pt: 'os filhos de Barcos, os filhos de Sísera, os filhos de Tamá,' },
      { v: 56, en: 'the children of Neziah, the children of Hatipha.', pt: 'os filhos de Nezias, os filhos de Hatifa,' },
      { v: 57, en: 'The children of Solomon’s servants: the children of Sotai, the children of Sophereth, the children of Perida,', pt: 'os filhos dos servos de Salomão: os filhos de Sotai, os filhos de Soforete, os filhos de Perida,' },
      { v: 58, en: 'the children of Jaala, the children of Darkon, the children of Giddel,', pt: 'os filhos de Jaala, os filhos de Darcom, os filhos de Gidel,' },
      { v: 59, en: 'the children of Shephatiah, the children of Hattil, the children of Pochereth Hazzebaim, the children of Amon.', pt: 'os filhos de Sefatias, os filhos de Hatil, os filhos de Paquerete-Hazebaim e os filhos de Amom.' },
      { v: 60, en: 'All the temple servants, and the children of Solomon’s servants, were three hundred ninety-two.', pt: 'Todos os netinins e os filhos dos servos de Salomão, eram trezentos e noventa e dois.' },
      { v: 61, en: 'These were those who went up from Tel Melah, Tel Harsha, Cherub, Addon, and Immer; but they could not show their fathers’ houses, nor their offspring, whether they were of Israel:', pt: 'Estes foram os que subiram de Tel-Mela, Tel-Harsa, Querube, Adom, e Imer; porém não puderam provar que as suas casas paternas e as sua linhagem eram de Israel:' },
      { v: 62, en: 'The children of Delaiah, the children of Tobiah, the children of Nekoda, six hundred forty-two.', pt: 'os filhos de Dalaías, os filhos de Tobias, os filhos de Necoda, seiscentos e quarenta e dois.' },
      { v: 63, en: 'Of the priests: the children of Hobaiah, the children of Hakkoz, the children of Barzillai, who took a wife of the daughters of Barzillai the Gileadite, and was called after their name.', pt: 'E dos sacerdotes: os filhos de Hobaías, os filhos Hacoz, os filhos de Barzilai, que tomara por mulher uma das filhas Barzilai, o gileadita, e que foi chamado do seu nome.' },
      { v: 64, en: 'These searched for their genealogical records, but couldn’t find them. Therefore were they deemed disqualified and removed from the priesthood.', pt: 'Estes buscaram o seu registro entre os arrolados nos registros genealógicos, mas não foi encontrado; pelo que, tidos por imundos, foram excluídos do sacerdócio.' },
      { v: 65, en: 'The governor told that they should not eat of the most holy things until a priest stood up to minister with Urim and Thummim.', pt: 'E o governador lhes disse que não comesse das coisas sagradas, até que se levantasse um sacerdote com Urim e Tumim.' },
      { v: 66, en: 'The whole assembly together was forty-two thousand three hundred sixty,', pt: 'Toda esta congregação junta somava quarenta e dois mil trezentos e sessenta;' },
      { v: 67, en: 'besides their male servants and their female servants, of whom there were seven thousand three hundred thirty-seven; and they had two hundred forty-five singing men and singing women.', pt: 'afora os seus servos e as suas servas, que foram sete mil trezentos e trinta e sete; e tinham duzentos e quarenta e cinco cantores e cantoras.' },
      { v: 68, en: 'Their horses were seven hundred thirty-six; their mules, two hundred forty-five;', pt: 'Os seus cavalos foram setecentos e trinta e seis; os seus mulos, duzentos e quarenta e cinco;' },
      { v: 69, en: 'their camels, four hundred thirty-five; their donkeys, six thousand seven hundred twenty.', pt: 'os seus camelos, quatrocentos e trinta e cinco; e os seus jumentos, seis mil setecentos e vinte.' },
      { v: 70, en: 'Some from among the heads of fathers’ households gave to the work. The governor gave to the treasury one thousand darics of gold, fifty basins, and five hundred thirty priests’ garments.', pt: 'Ora, alguns dos cabeças das casas paternas contribuíram para a obra. O governador deu para a tesouraria mil dários de ouro, cinqüenta bacias, e quinhentas e trinta vestes sacerdotais.' },
      { v: 71, en: 'Some of the heads of fathers’ households gave into the treasury of the work twenty thousand darics of gold, and two thousand two hundred minas of silver.', pt: 'E alguns dos cabeças das casas paternas deram para a tesouraria da obra vinte mil dáricos de ouro, e duas mil e duzentas minas de prata.' },
      { v: 72, en: 'That which the rest of the people gave was twenty thousand darics of gold, plus two thousand minas of silver, and sixty-seven priests’ garments.', pt: 'O que o resto do povo deu foram vinte mil dáricos de ouro, duas mil minas de prata, e sessenta e sete vestes sacerdotais.' },
      { v: 73, en: 'So the priests, the Levites, the gatekeepers, the singers, some of the people, the temple servants, and all Israel, lived in their cities. When the seventh month had come, the children of Israel were in their cities.', pt: 'Os sacerdotes, os levitas, os porteiros, os cantores, alguns dentre o povo, os netinins e todo o Israel habitaram nas suas cidades. Quando chegou o sétimo mês, já se achavam os filhos de Israel nas suas cidades.' },
    ],
    8: [
      { v: 1, en: 'All the people gathered themselves together as one man into the wide place that was in front of the water gate; and they spoke to Ezra the scribe to bring the book of the law of Moses, which Yahweh had commanded to Israel.', pt: 'Então todo o povo se ajuntou como um só homem, na praça diante da porta das águas; e disseram a Esdras, o escriba, que trouxesse o livro da lei de Moisés, que o Senhor tinha ordenado a Israel.' },
      { v: 2, en: 'Ezra the priest brought the law before the assembly, both men and women, and all who could hear with understanding, on the first day of the seventh month.', pt: 'E Esdras, o sacerdote, trouxe a lei perante a congregação, tanto de homens como de mulheres, e de todos os que podiam ouvir com entendimento, no primeiro dia do sétimo mês.' },
      { v: 3, en: 'He read from it before the wide place that was in front of the water gate from early morning until midday, in the presence of the men and the women, and of those who could understand. The ears of all the people were attentive to the book of the law.', pt: 'E leu nela diante da praça que está fronteira à porta das águas, desde a alva até o meio-dia, na presença dos homens e das mulheres, e dos que podiam entender; e os ouvidos de todo o povo estavam atentos ao livro da lei.' },
      { v: 4, en: 'Ezra the scribe stood on a pulpit of wood, which they had made for the purpose; and beside him stood Mattithiah, Shema, Anaiah, Uriah, Hilkiah, and Maaseiah, on his right hand; and on his left hand, Pedaiah, Mishael, Malchijah, Hashum, Hashbaddanah, Zechariah, and Meshullam.', pt: 'Esdras, o escriba, ficava em pé sobre um estrado de madeira, que fizeram para esse fim e estavam em pé junto a ele, à sua direita, Matitias, Sema, Ananías, Urias, Hilquias e Maaséias; e à sua esquerda, Pedaías, Misael, Malquias, Hasum, Hasbadana, Zacarias e Mesulão.' },
      { v: 5, en: 'Ezra opened the book in the sight of all the people (for he was above all the people), and when he opened it, all the people stood up.', pt: 'E Esdras abriu o livro à vista de todo o povo (pois estava acima de todo o povo); e, abrindo-o ele, todo o povo se pôs em pé.' },
      { v: 6, en: 'Then Ezra blessed Yahweh, the great God. All the people answered, “Amen, Amen,” with the lifting up of their hands. They bowed their heads, and worshiped Yahweh with their faces to the ground.', pt: 'Então Esdras bendisse ao Senhor, o grande Deus; e todo povo, levantando as mãos, respondeu: Amém! amém! E, inclinando-se, adoraram ao Senhor, com os rostos em terra.' },
      { v: 7, en: 'Also Jeshua, Bani, Sherebiah, Jamin, Akkub, Shabbethai, Hodiah, Maaseiah, Kelita, Azariah, Jozabad, Hanan, Pelaiah, and the Levites, caused the people to understand the law; and the people stayed in their place.', pt: 'Também Jesuá, Bani, Serebias, Jamim, Acube; Sabetai, Hodias, Maaséias, Quelita, Azarias, Jozabade, Hanã, Pelaías e os levitas explicavam ao povo a lei; e o povo estava em pé no seu lugar.' },
      { v: 8, en: 'They read in the book, in the law of God, distinctly; and they gave the sense, so that they understood the reading.', pt: 'Assim leram no livro, na lei de Deus, distintamente; e deram o sentido, de modo que se entendesse a leitura.' },
      { v: 9, en: 'Nehemiah, who was the governor, and Ezra the priest and scribe, and the Levites who taught the people, said to all the people, “Today is holy to Yahweh your God. Don’t mourn, nor weep.” For all the people wept when they heard the words of the law.', pt: 'E Neemias, que era o governador, e Esdras, sacerdote e escriba, e os levitas que ensinavam o povo, disseram a todo o povo: Este dia é consagrado ao Senhor vosso Deus; não pranteeis nem choreis. Pois todo o povo chorava, ouvindo as palavras da lei.' },
      { v: 10, en: 'Then he said to them, “Go your way. Eat the fat, drink the sweet, and send portions to him for whom nothing is prepared, for today is holy to our Lord. Don’t be grieved, for the joy of Yahweh is your strength.”', pt: 'Disse-lhes mais: Ide, comei as gorduras, e bebei as doçuras, e enviai porções aos que não têm nada preparado para si; porque este dia é consagrado ao nosso Senhor. Portanto não vos entristeçais, pois a alegria do Senhor é a vossa força.' },
      { v: 11, en: 'So the Levites calmed all the people, saying, “Hold your peace, for the day is holy. Don’t be grieved.”', pt: 'Os levitas, pois, fizeram calar todo o povo, dizendo: Calai-vos, porque este dia é santo; por isso não vos entristeçais.' },
      { v: 12, en: 'All the people went their way to eat, to drink, to send portions, and to celebrate, because they had understood the words that were declared to them.', pt: 'Então todo o povo se foi para comer e beber, e para enviar porções, e para fazer grande regozijo, porque tinha entendido as palavras que lhe foram referidas.' },
      { v: 13, en: 'On the second day, the heads of fathers’ households of all the people, the priests, and the Levites were gathered together to Ezra the scribe, to study the words of the law.', pt: 'Ora, no dia seguinte ajuntaram-se os cabeças das casas paternas de todo o povo, os sacerdotes e os levitas, na presença de Esdras, o escriba, para examinarem as palavras da lei;' },
      { v: 14, en: 'They found written in the law how Yahweh had commanded by Moses that the children of Israel should dwell in booths in the feast of the seventh month;', pt: 'e acharam escrito na lei que o Senhor, por intermédio de Moisés, ordenara que os filhos de Israel habitassem em cabanas durante a festa do sétimo mês;' },
      { v: 15, en: 'and that they should publish and proclaim in all their cities, and in Jerusalem, saying, “Go out to the mountain, and get olive branches, branches of wild olive, myrtle branches, palm branches, and branches of thick trees, to make temporary shelters, as it is written.”', pt: 'e que publicassem e fizessem passar pregão por todas as suas cidades, e em ramos de oliveiras, de zambujeiros e de murtas, folhas de palmeiras, e ramos de outras árvores frondosas, para fazerdes cabanas, como está escrito.' },
      { v: 16, en: 'So the people went out, and brought them, and made themselves temporary shelters, everyone on the roof of his house, in their courts, in the courts of God’s house, in the wide place of the water gate, and in the wide place of Ephraim’s gate.', pt: 'Saiu, pois, o povo e trouxe os ramos; e todos fizeram para si cabanas, cada um no eirado da sua casa, nos seus pátios, nos átrios da casa de Deus, na praça da porta das águas, e na praça da porta de Efraim.' },
      { v: 17, en: 'All the assembly of those who had come back out of the captivity made temporary shelters, and lived in the booths; for since the days of Jeshua the son of Nun to that day the children of Israel had not done so. There was very great gladness.', pt: 'E toda a comunidade dos que tinham voltado do cativeiro fez cabanas, e habitaram nelas; pois não tinham feito assim os filhos de Israel desde os dias de Josué, filho de Num, até aquele dia. E houve mui grande regozijo.' },
      { v: 18, en: 'Also day by day, from the first day to the last day, he read in the book of the law of God. They kept the feast seven days; and on the eighth day was a solemn assembly, according to the ordinance.', pt: 'E Esdras leu no livro da lei de Deus todos os dias, desde o primeiro até o último; e celebraram a festa por sete dias, e no oitavo dia houve uma assembléia solene, segundo a ordenança.' },
    ],
    9: [
      { v: 1, en: 'Now in the twenty-fourth day of this month the children of Israel were assembled with fasting, with sackcloth, and dirt on them.', pt: 'Ora, no dia vinte e quatro desse mês, se ajuntaram os filhos de Israel em jejum, vestidos de sacos e com terra sobre as cabeças.' },
      { v: 2, en: 'The offspring of Israel separated themselves from all foreigners, and stood and confessed their sins, and the iniquities of their fathers.', pt: 'E os da linhagem de Israel se apartaram de todos os estrangeiros, puseram-se em pé e confessaram os seus pecados e as iniquidades de seus pais.' },
      { v: 3, en: 'They stood up in their place, and read in the book of the law of Yahweh their God a fourth part of the day; and a fourth part they confessed, and worshiped Yahweh their God.', pt: 'E, levantando-se no seu lugar, leram no livro da lei do Senhor seu Deus, uma quarta parte do dia; e outra quarta parte fizeram confissão, e adoraram ao Senhor seu Deus.' },
      { v: 4, en: 'Then Jeshua, Bani, Kadmiel, Shebaniah, Bunni, Sherebiah, Bani, and Chenani of the Levites stood up on the stairs, and cried with a loud voice to Yahweh their God.', pt: 'Então Jesuá, Bani, Cadmiel, Sebanias, Buni, Serebias, Bani e Quenâni se puseram em pé sobre os degraus dos levitas, e clamaram em alta voz ao Senhor seu Deus.' },
      { v: 5, en: 'Then the Levites, Jeshua, and Kadmiel, Bani, Hashabneiah, Sherebiah, Hodiah, Shebaniah, and Pethahiah, said, “Stand up and bless Yahweh your God from everlasting to everlasting! Blessed be your glorious name, which is exalted above all blessing and praise!', pt: 'E os levitas Jesuá, Cadmiel, Bani, Hasabnéias, Serebias, Hodias, Sebanias e Petaías disseram: Levantai-vos, bendizei ao Senhor vosso Deus de eternidade em eternidade. Bendito seja o teu glorioso nome, que está exaltado sobre toda benção e louvor.' },
      { v: 6, en: 'You are Yahweh, even you alone. You have made heaven, the heaven of heavens, with all their army, the earth and all things that are on it, the seas and all that is in them, and you preserve them all. The army of heaven worships you.', pt: 'Tu, só tu, és Senhor; tu fizeste o céu e o céu dos céus, juntamente com todo o seu exército, a terra e tudo quanto nela existe, os mares e tudo quanto neles já, e tu os conservas a todos, e o exército do céu te adora.' },
      { v: 7, en: 'You are Yahweh, the God who chose Abram, brought him out of Ur of the Chaldees, gave him the name of Abraham,', pt: 'Tu és o Senhor, o Deus que elegeste a Abrão, e o tiraste de Ur dos caldeus, e lhe puseste por nome Abraão;' },
      { v: 8, en: 'found his heart faithful before you, and made a covenant with him to give the land of the Canaanite, the Hittite, the Amorite, the Perizzite, the Jebusite, and the Girgashite, to give it to his offspring, and have performed your words; for you are righteous.', pt: 'e achaste o seu coração fiel perante ti, e fizeste com ele o pacto de que darias à sua descendência a terra dos cananeus, dos heteus, dos amorreus, dos perizeus, dos jebuseus e dos girgaseus; e tu cumpriste as tuas palavras, pois és justo.' },
      { v: 9, en: '“You saw the affliction of our fathers in Egypt, and heard their cry by the Red Sea,', pt: 'Também viste a aflição de nossos pais no Egito, e ouviste o seu clamor junto ao Mar Vermelho;' },
      { v: 10, en: 'and showed signs and wonders against Pharaoh, and against all his servants, and against all the people of his land; for you knew that they dealt proudly against them, and made a name for yourself, as it is today.', pt: 'e o operaste sinais e prodígios contra Faraó; e contra todos os seus servos, e contra todo o povo da sua terra; pois sabias com que soberba eles os haviam tratado; e assim adquiriste renome, como hoje se vê.' },
      { v: 11, en: 'You divided the sea before them, so that they went through the middle of the sea on the dry land; and you cast their pursuers into the depths, as a stone into the mighty waters.', pt: 'Fendente o mar diante deles, de modo que passaram pelo meio do mar, em seco; e lançaste os seus perseguidores nas profundezas, como uma pedra nas águas impetuosas.' },
      { v: 12, en: 'Moreover, in a pillar of cloud you led them by day; and in a pillar of fire by night, to give them light in the way in which they should go.', pt: 'Além disso tu os guiaste de dia por uma coluna de nuvem e de noite por uma coluna de fogo, para os alumiares no caminho por onde haviam de ir.' },
      { v: 13, en: '“You also came down on Mount Sinai, and spoke with them from heaven, and gave them right ordinances and true laws, good statutes and commandments,', pt: 'Desceste sobre o monte Sinai, do céu falaste com eles, e lhes deste juízos retos e leis verdadeiras, bons estatutos e mandamentos;' },
      { v: 14, en: 'and made known to them your holy Sabbath, and commanded them commandments, statutes, and a law, by Moses your servant,', pt: 'o teu santo sábado lhes fizeste conhecer; e lhes ordenaste mandamentos e estatutos e uma lei, por intermédio de teu servo Moisés.' },
      { v: 15, en: 'and gave them bread from the sky for their hunger, and brought water out of the rock for them for their thirst, and commanded them that they should go in to possess the land which you had sworn to give them.', pt: 'Do céu lhes deste pão quando tiveram fome, e da rocha fizeste brotar água quando tiveram sede; e lhes ordenaste que entrassem para possuir a terra que com juramento lhes havias prometido dar.' },
      { v: 16, en: '“But they and our fathers behaved proudly, hardened their neck, didn’t listen to your commandments,', pt: 'Eles, porém, os nossos pais, se houveram soberbamente e endureceram a cerviz, e não deram ouvidos aos teus mandamentos,' },
      { v: 17, en: 'and refused to obey. They weren’t mindful of your wonders that you did among them, but hardened their neck, and in their rebellion appointed a captain to return to their bondage. But you are a God ready to pardon, gracious and merciful, slow to anger, and abundant in loving kindness, and didn’t forsake them.', pt: 'recusando ouvir-te e não se lembrando das tuas maravilhas, que fizeste no meio deles; antes endureceram a cerviz e, na sua rebeldia, levantaram um chefe, a fim de voltarem para sua servidão. Tu, porém, és um Deus pronto para perdoar, clemente e misericordioso, tardio em irar-te e grande em beneficência, e não os abandonaste.' },
      { v: 18, en: 'Yes, when they had made themselves a molten calf, and said, ‘This is your God who brought you up out of Egypt,’ and had committed awful blasphemies;', pt: 'Ainda mesmo quando eles fizeram para si um bezerro de fundição, e disseram: Este é o teu Deus, que te tirou do Egito, e cometeram grandes blasfêmias,' },
      { v: 19, en: 'yet you in your manifold mercies didn’t forsake them in the wilderness. The pillar of cloud didn’t depart from over them by day, to lead them in the way; neither did the pillar of fire by night, to show them light, and the way in which they should go.', pt: 'todavia tu, pela multidão das tuas misericórdias, não os abandonaste no deserto. A coluna de nuvem não se apartou deles de dia, para os guiar pelo caminho, nem a coluna de fogo de noite, para lhes alumiar o caminho por onde haviam de ir.' },
      { v: 20, en: 'You gave also your good Spirit to instruct them, and didn’t withhold your manna from their mouth, and gave them water for their thirst.', pt: 'Também lhes deste o teu bom espírito para os ensinar, e o teu maná não retiraste da tua boca, e água lhes deste quando tiveram sede.' },
      { v: 21, en: '“Yes, forty years you sustained them in the wilderness. They lacked nothing. Their clothes didn’t grow old, and their feet didn’t swell.', pt: 'Sim, por quarenta anos os sustentaste no deserto; não lhes faltou coisa alguma; a sua roupa não envelheceu, e o seus pés não se incharam.' },
      { v: 22, en: 'Moreover you gave them kingdoms and peoples, which you allotted according to their portions. So they possessed the land of Sihon, even the land of the king of Heshbon, and the land of Og king of Bashan.', pt: 'Além disso lhes deste reinos e povos, que lhes repartiste em porções; assim eles possuíram a terra de Siom, a saber; a terra do rei de Hesbom, e a terra de Ogue, rei de Basã.' },
      { v: 23, en: 'You also multiplied their children as the stars of the sky, and brought them into the land concerning which you said to their fathers, that they should go in to possess it.', pt: 'Outrossim mulplicaste os seus filhos como as estrelas do céu, e os introduziste na terra de que tinhas dito a seus pais que nela entrariam para a possuírem.' },
      { v: 24, en: '“So the children went in and possessed the land, and you subdued before them the inhabitants of the land, the Canaanites, and gave them into their hands, with their kings and the peoples of the land, that they might do with them as they pleased.', pt: 'Os filhos, pois, entraram e possuíram a terra; e abateste perante eles, os moradores da terra, os cananeus, e lhos entregaste nas mãos, como também os seus reis, e os povos da terra, para fazerem deles conforme a sua vontade.' },
      { v: 25, en: 'They took fortified cities and a rich land, and possessed houses full of all good things, cisterns dug out, vineyards, and olive groves, and fruit trees in abundance. So they ate, were filled, became fat, and delighted themselves in your great goodness.', pt: 'Tomaram cidades fortificadas e uma terra fértil, e possuíram casas cheias de toda sorte de coisas boas, cisternas cavadas, vinhas e olivais, e árvores frutíferas em abundância; comeram, pois, fartaram-se e engordaram, e viveram em delícias, pela tua grande bondade.' },
      { v: 26, en: '“Nevertheless they were disobedient, and rebelled against you, cast your law behind their back, killed your prophets that testified against them to turn them again to you, and they committed awful blasphemies.', pt: 'Não obstante foram desobedientes, e se rebelaram contra ti; lançaram a tua lei para trás das costas, e mataram os teus profetas que protestavam contra eles para que voltassem a ti; assim cometeram grandes provocações.' },
      { v: 27, en: 'Therefore you delivered them into the hand of their adversaries, who distressed them. In the time of their trouble, when they cried to you, you heard from heaven; and according to your manifold mercies you gave them saviors who saved them out of the hands of their adversaries.', pt: 'Pelo que os entregaste nas mãos dos seus adversários, que os afligiram; mas no templo da sua angústia, quando eles clamaram a ti, tu os ouviste do céu; e segundo a multidão das tuas misericórdias lhes deste libertadores que os libertaram das mãos de seus adversários.' },
      { v: 28, en: 'But after they had rest, they did evil again before you; therefore left you them in the hands of their enemies, so that they had the dominion over them; yet when they returned, and cried to you, you heard from heaven; and many times you delivered them according to your mercies,', pt: 'Mas, tendo alcançado repouso, tornavam a fazer o mal diante de ti,; portanto tu os deixavas nas mãos dos seus inimigos, de modo que estes dominassem sobre eles; todavia quando eles voltavam e clamavam a ti, tu os ouvias do céu, e segundo a tua misericórdia os livraste muitas vezes;' },
      { v: 29, en: 'and testified against them, that you might bring them again to your law. Yet they were arrogant, and didn’t listen to your commandments, but sinned against your ordinances (which if a man does, he shall live in them), turned their backs, stiffened their neck, and would not hear.', pt: 'e testemunhaste contra eles, para os fazerdes voltar para a tua lei; contudo eles se houveram soberbamente, e não deram ouvidos aos teus mandamentos, mas pecaram contra os teus juízos, pelos quais viverá o homem que os cumprir; viraram o ombro, endureceram a cerviz e não quiseram ouvir.' },
      { v: 30, en: 'Yet many years you put up with them, and testified against them by your Spirit through your prophets. Yet would they not give ear. Therefore you gave them into the hand of the peoples of the lands.', pt: 'Não obstante, por muitos anos os aturaste, e testemunhaste contra eles pelo teu Espírito, por intermédio dos teus profetas; todavia eles não quiseram dar ouvidos; pelo que os entregaste nas mãos dos povos de outras terras.' },
      { v: 31, en: '“Nevertheless in your manifold mercies you did not make a full end of them, nor forsake them; for you are a gracious and merciful God.', pt: 'Contudo pela tua grande misericórdia não os destruíste de todo, nem os abandonaste, porque és um Deus clemente e misericordioso.' },
      { v: 32, en: 'Now therefore, our God, the great, the mighty, and the awesome God, who keeps covenant and loving kindness, don’t let all the travail seem little before you, that has come on us, on our kings, on our princes, on our priests, on our prophets, on our fathers, and on all your people, since the time of the kings of Assyria to this day.', pt: 'Agora, pois, ó nosso Deus, Deus grande, poderoso e temível, que guardas o pacto e a beneficência, não tenhas em pouca conta toda a aflição que nos alcançou a nós, a nossos reis, a nossos príncipes, a nossos sacerdotes, a nossos profetas, a nossos pais e a todo o teu povo, desde os dias dos reis da Assíria até o dia de hoje.' },
      { v: 33, en: 'However you are just in all that has come on us; for you have dealt truly, but we have done wickedly.', pt: 'Tu, porém, és justo em tudo quanto tem vindo sobre nós; pois tu fielmente procedeste, mas nós perversamente.' },
      { v: 34, en: 'Also our kings, our princes, our priests, and our fathers have not kept your law, nor listened to your commandments and your testimonies with which you testified against them.', pt: 'Os nossos reis, os nossos príncipes, os nossos sacerdotes, e os nossos pais não têm guardado a tua lei, nem têm dado ouvidos aos teus mandamentos e aos teus testemunhos, com que testificaste contra eles.' },
      { v: 35, en: 'For they have not served you in their kingdom, and in your great goodness that you gave them, and in the large and rich land which you gave before them. They did not turn from their wicked works.', pt: 'Porque eles, no seu reino, na muita abundância de bens que lhes deste, na terra espaçosa e fértil que puseste diante deles, não te serviram, nem se converteram de suas más obras.' },
      { v: 36, en: '“Behold, we are servants today, and as for the land that you gave to our fathers to eat its fruit and its good, behold, we are servants in it.', pt: 'Eis que hoje somo escravos; e quanto à terra que deste a nossos pais, para comerem o seu fruto e o seu bem, eis que somos escravos nela.' },
      { v: 37, en: 'It yields much increase to the kings whom you have set over us because of our sins. Also they have power over our bodies and over our livestock, at their pleasure, and we are in great distress.', pt: 'E ela multiplica os seus produtos para os reis que puseste sobre nós por causa dos nossos pecados; também eles dominam sobre os nossos corpos e sobre o nosso gado como bem lhes apraz, e estamos em grande angústia.' },
      { v: 38, en: 'Yet for all this, we make a sure covenant, and write it; and our princes, our Levites, and our priests, seal it.”', pt: 'Contudo, por causa de tudo isso firmamos um pacto e o escrevemos; e selam-no os nossos príncipes, os nossos levitas e os nossos sacerdotes.' },
    ],
    10: [
      { v: 1, en: 'Now those who sealed were: Nehemiah the governor, the son of Hacaliah, and Zedekiah,', pt: 'Os que selaram foram: Neemias, o governador, filho de Hacalias, Zedequias,' },
      { v: 2, en: 'Seraiah, Azariah, Jeremiah,', pt: 'Seraías, Azarias, Jeremias,' },
      { v: 3, en: 'Pashhur, Amariah, Malchijah,', pt: 'Pasur, Amarias, Malquias,' },
      { v: 4, en: 'Hattush, Shebaniah, Malluch,', pt: 'Hatus, Sebanias, Maluque,' },
      { v: 5, en: 'Harim, Meremoth, Obadiah,', pt: 'Harim, Meremote, Obadias,' },
      { v: 6, en: 'Daniel, Ginnethon, Baruch,', pt: 'Daniel, Ginetom, Baruque,' },
      { v: 7, en: 'Meshullam, Abijah, Mijamin,', pt: 'Mesulão, Abias, Miamim,' },
      { v: 8, en: 'Maaziah, Bilgai, and Shemaiah. These were the priests.', pt: 'Maazias, Bilgai e Semaías;estes foram os sacerdotes.' },
      { v: 9, en: 'The Levites: namely, Jeshua the son of Azaniah, Binnui of the sons of Henadad, Kadmiel;', pt: 'E os levitas: Jesuá, filho de Azanias, Binuí, dos filhos de Henadade, Cadmiel,' },
      { v: 10, en: 'and their brothers, Shebaniah, Hodiah, Kelita, Pelaiah, Hanan,', pt: 'e seus irmãos, Sebanias, Hodias, Quelita, Pelaías, Hanã,' },
      { v: 11, en: 'Mica, Rehob, Hashabiah,', pt: 'Mica, Reobe, Hasabias,' },
      { v: 12, en: 'Zaccur, Sherebiah, Shebaniah,', pt: 'Zacur, Serebias, Sebanias,' },
      { v: 13, en: 'Hodiah, Bani, and Beninu.', pt: 'Hodias, Bani e Benínu.' },
      { v: 14, en: 'The chiefs of the people: Parosh, Pahathmoab, Elam, Zattu, Bani,', pt: 'Os chefes do povo: Parós, Paate-Moabe, Elão, Zatu, Bani,' },
      { v: 15, en: 'Bunni, Azgad, Bebai,', pt: 'Buni, Azgade, Bebai,' },
      { v: 16, en: 'Adonijah, Bigvai, Adin,', pt: 'Adonias, Bigvai, Adim,' },
      { v: 17, en: 'Ater, Hezekiah, Azzur,', pt: 'Ater, Ezequias, Azur,' },
      { v: 18, en: 'Hodiah, Hashum, Bezai,', pt: 'Hodias, Asum, Bezai,' },
      { v: 19, en: 'Hariph, Anathoth, Nobai,', pt: 'Harife, Anotote, Nobai,' },
      { v: 20, en: 'Magpiash, Meshullam, Hezir,', pt: 'Magpias, Mesulão, Hezir,' },
      { v: 21, en: 'Meshezabel, Zadok, Jaddua,', pt: 'Mesezabel, Zadoque, Jadua,' },
      { v: 22, en: 'Pelatiah, Hanan, Anaiah,', pt: 'Pelatias, Hanã, Anaías,' },
      { v: 23, en: 'Hoshea, Hananiah, Hasshub,', pt: 'Oséias, Hananias, Ananías,' },
      { v: 24, en: 'Hallohesh, Pilha, Shobek,', pt: 'Haloés, Pilá, Sobeque,' },
      { v: 25, en: 'Rehum, Hashabnah, Maaseiah,', pt: 'Reum, Hasabna, Maaséias,' },
      { v: 26, en: 'and Ahiah, Hanan, Anan,', pt: 'Aías, Hanã, Anã,' },
      { v: 27, en: 'Malluch, Harim, and Baanah.', pt: 'Maluque, Harim e Baaná.' },
      { v: 28, en: 'The rest of the people, the priests, the Levites, the gatekeepers, the singers, the temple servants, and all those who had separated themselves from the peoples of the lands to the law of God, their wives, their sons, and their daughters, everyone who had knowledge, and understanding—', pt: 'E o resto do povo, os sacerdotes, os porteiros, os cantores, os netinins, e todos os que se tinham separado dos povos de outras terras para seguir a lei de Deus, suas mulheres, seus filhos e suas filhas, todos os que tinham conhecimento e entendimento,' },
      { v: 29, en: 'they joined with their brothers, their nobles, and entered into a curse, and into an oath, to walk in God’s law, which was given by Moses the servant of God, and to observe and do all the commandments of Yahweh our Lord, and his ordinances and his statutes;', pt: 'aderiram a seus irmãos, os seus nobres, e convieram num juramento sob pena de maldição de que andariam na lei de Deus, a qual foi dada por intermédio de Moisés, servo de Deus, e de que guardariam e cumpririam todos os mandamentos do Senhor, nosso Senhor, e os seus juízos e os seus estatutos;' },
      { v: 30, en: 'and that we would not give our daughters to the peoples of the land, nor take their daughters for our sons;', pt: 'de que não daríamos as nossas filhas aos povos da terra, nem tomaríamos as filhas deles para os nossos filhos;' },
      { v: 31, en: 'and if the peoples of the land bring wares or any grain on the Sabbath day to sell, that we would not buy from them on the Sabbath, or on a holy day; and that we would forego the seventh year, and the exaction of every debt.', pt: 'de que, se os povos da terra trouxessem no dia de sábado qualquer mercadoria ou quaisquer cereais para venderem, nada lhes compraríamos no sábado, nem em dia santificado; e de que abriríamos mão do produto do sétimo ano e da cobrança nele de todas as dívidas.' },
      { v: 32, en: 'Also we made ordinances for ourselves, to charge ourselves yearly with the third part of a shekel for the service of the house of our God;', pt: 'Também sobre nós impusemos ordenanças, obrigando-nos a dar a cada ano a terça parte dum siclo para o serviço da casa do nosso Deus;' },
      { v: 33, en: 'for the show bread, for the continual meal offering, for the continual burnt offering, for the Sabbaths, for the new moons, for the set feasts, and for the holy things, and for the sin offerings to make atonement for Israel, and for all the work of the house of our God.', pt: 'para os pães da proposição, para a contínua oferta de cereais, para o contínuo holocausto dos sábados e das luas novas, para as festas fixas, para as coisas sagradas, para as ofertas pelo pecado a fim de fazer expiação por Israel, e para toda a obra da casa do nosso Deus.' },
      { v: 34, en: 'We cast lots, the priests, the Levites, and the people, for the wood offering, to bring it into the house of our God, according to our fathers’ houses, at times appointed, year by year, to burn on Yahweh our God’s altar, as it is written in the law;', pt: 'E nós, os sacerdotes, os levitas e o povo lançamos sortes acerca da oferta da lenha que havíamos de trazer à casa do nosso Deus, segundo as nossas casas paternas, a tempos determinados, de ano em ano, para se queimar sobre o altar do Senhor nosso Deus, como está escrito na lei.' },
      { v: 35, en: 'and to bring the first fruits of our ground, and the first fruits of all fruit of all kinds of trees, year by year, to Yahweh’s house;', pt: 'Também nos obrigamos a trazer de ano em ano à casa do Senhor as primícias de todos os frutos de todas as árvores;' },
      { v: 36, en: 'also the firstborn of our sons, and of our livestock, as it is written in the law, and the firstborn of our herds and of our flocks, to bring to the house of our God, to the priests who minister in the house of our God;', pt: 'e a trazer os primogênitos dos nossos filhos, e os do nosso gado, como está escrito na lei, e os primogênitos das nossas manadas e dos nossos rebanhos à casa do nosso Deus, aos sacerdotes que ministram na casa do nosso Deus;' },
      { v: 37, en: 'and that we should bring the first fruits of our dough, our wave offerings, the fruit of all kinds of trees, and the new wine and the oil, to the priests, to the rooms of the house of our God; and the tithes of our ground to the Levites; for they, the Levites, take the tithes in all the cities of our tillage.', pt: 'e as primícias da nossa mas, e as nossas ofertas alçadas, e o fruto de toda sorte de árvores, para as câmaras da casa de nosso Deus; e os dízimos da nossa terra aos levitas; pois eles, os levitas, recebem os dízimos em todas as cidades por onde temos lavoura.' },
      { v: 38, en: 'The priest the son of Aaron shall be with the Levites, when the Levites take tithes. The Levites shall bring up the tithe of the tithes to the house of our God, to the rooms, into the treasure house.', pt: 'E o sacerdote, filho de Arão, deve estar com os levitas quando estes receberem os dízimos; e os levitas devem trazer o dízimo dos dízimos à casa do nosso Deus, para as câmaras, dentro da tesouraria.' },
      { v: 39, en: 'For the children of Israel and the children of Levi shall bring the wave offering of the grain, of the new wine, and of the oil, to the rooms, where the vessels of the sanctuary are, and the priests who minister, with the gatekeepers and the singers. We will not forsake the house of our God.', pt: 'Pois os filhos de Israel e os filhos de Levi devem trazer ofertas alçadas dos cereais, do mosto e do azeite para aquelas câmaras, em que estão os utensílios do santuário, como também os sacerdotes que ministram, e os porteiros, e os cantores; e assim não negligenciarmos a casa do nosso Deus.' },
    ],
    11: [
      { v: 1, en: 'The princes of the people lived in Jerusalem. The rest of the people also cast lots, to bring one of ten to dwell in Jerusalem the holy city, and nine parts in the other cities.', pt: 'Ora, os príncipes do povo habitaram em Jerusalém; e o restante do povo lançou sortes, para atirar um de cada dez que habitasse na santa cidade de Jerusalém, ficando nove nas outras cidades.' },
      { v: 2, en: 'The people blessed all the men who willingly offered themselves to dwell in Jerusalem.', pt: 'E o povo bendisse todos os homens que voluntariamente se ofereceram para habitar em Jerusalém.' },
      { v: 3, en: 'Now these are the chiefs of the province who lived in Jerusalem; but in the cities of Judah everyone lived in his possession in their cities: Israel, the priests, the Levites, the temple servants, and the children of Solomon’s servants.', pt: 'Estes, pois, são os chefes da província que habitaram em Jerusalém; porém nas cidades de Judá habitou cada um na sua possessão, nas suas cidades, a saber, Israel, os sacerdotes, os levitas, os netinins e os filhos dos servos de Salomão.' },
      { v: 4, en: 'Some of the children of Judah and of the children of Benjamin lived in Jerusalem. Of the children of Judah: Athaiah the son of Uzziah, the son of Zechariah, the son of Amariah, the son of Shephatiah, the son of Mahalalel, of the children of Perez;', pt: 'E habitaram em Jerusalém alguns dos filhos de Judá e dos filhos de Benjamim. Dos filhos de Judá: Ataías, filho de Uzias, filho de Zacarias, filho de Amarias, filho de Sefatias, filho de Maalelel, dos filhos de Pérez;' },
      { v: 5, en: 'and Maaseiah the son of Baruch, the son of Colhozeh, the son of Hazaiah, the son of Adaiah, the son of Joiarib, the son of Zechariah, the son of the Shilonite.', pt: 'e Maaséias, filho de Baruque, filho de Col-Hoze, filho de Hazaías, filho de Adaías, filho de Joiaribe, filho de Zacarias, filho de Silôni.' },
      { v: 6, en: 'All the sons of Perez who lived in Jerusalem were four hundred sixty-eight valiant men.', pt: 'Todos os filhos de Pérez que habitaram em Jerusalém foram quatrocentos e sessenta e oito homens valentes.' },
      { v: 7, en: 'These are the sons of Benjamin: Sallu the son of Meshullam, the son of Joed, the son of Pedaiah, the son of Kolaiah, the son of Maaseiah, the son of Ithiel, the son of Jeshaiah.', pt: 'São estes os filhos de Benjamim: Salu, filho de Mesulão, filho de Joede, filho de Pedaías, filho de Colaías, filho de Maaséias, filho de Itiel, filho de Jesaías.' },
      { v: 8, en: 'After him Gabbai, Sallai, nine hundred twenty-eight.', pt: 'E depois dele Gabai, Salai, ...novecentos e vinte e oito.' },
      { v: 9, en: 'Joel the son of Zichri was their overseer; and Judah the son of Hassenuah was second over the city.', pt: 'Joel, filho de Zicri, superintendente sobre eles; e Judá, filho de Senua, o segundo sobre a cidade.' },
      { v: 10, en: 'Of the priests: Jedaiah the son of Joiarib, Jachin,', pt: 'Dos sacerdotes: Jedaías, filho de Joiaribe, Jaquim,' },
      { v: 11, en: 'Seraiah the son of Hilkiah, the son of Meshullam, the son of Zadok, the son of Meraioth, the son of Ahitub, the ruler of God’s house,', pt: 'Seraías, filho de Hilquias, filho de Mesulão, filho de Zadoque, filho de Meraiote, filho de Altube, príncipe sobre a casa de Deus;' },
      { v: 12, en: 'and their brothers who did the work of the house, eight hundred twenty-two; and Adaiah the son of Jeroham, the son of Pelaliah, the son of Amzi, the son of Zechariah, the son of Pashhur, the son of Malchijah,', pt: 'e seus irmãos que faziam a obra da casa, oitocentos e vinte e dois; e Adaías, filho de Jeroão, filho de Pelalias, filho de Anzi, filho de Zacarias, filha de Pasur, filho de Malquias,' },
      { v: 13, en: 'and his brothers, chiefs of fathers’ households, two hundred forty-two; and Amashsai the son of Azarel, the son of Ahzai, the son of Meshillemoth, the son of Immer,', pt: 'e seus irmãos, cabeças de casas paternas, duzentos e quarenta e dois; e Amassai, filho de Azarel, filho de Aazai, filho de Mesilemote, filho de Imer,' },
      { v: 14, en: 'and their brothers, mighty men of valor, one hundred twenty-eight; and their overseer was Zabdiel, the son of Haggedolim.', pt: 'e os irmãos deles, homens valentes, cento e vinte e oito; e o superintendente sobre eles era Zabdiel, filho de Hagedolim.' },
      { v: 15, en: 'Of the Levites: Shemaiah the son of Hasshub, the son of Azrikam, the son of Hashabiah, the son of Bunni;', pt: 'Dos levitas: Semaías, filho de Hassube, filho de Azricão, filho de Hasabias, filho de Buni;' },
      { v: 16, en: 'and Shabbethai and Jozabad, of the chiefs of the Levites, who had the oversight of the outward business of God’s house;', pt: 'Sabetai e Jozabade, dos cabeças dos levitas, presidiam o serviço externo da casa de Deus;' },
      { v: 17, en: 'and Mattaniah the son of Mica, the son of Zabdi, the son of Asaph, who was the chief to begin the thanksgiving in prayer, and Bakbukiah, the second among his brothers; and Abda the son of Shammua, the son of Galal, the son of Jeduthun.', pt: 'Matanias, filho de Mica, filho de Zabdi, filho de Asafe, o dirigente que iniciava as ações de graças na oração, e Baquebuquias, o segundo entre seus irmãos; depois Abda, filho de Samua, filho de Galal, filho de Jedútun.' },
      { v: 18, en: 'All the Levites in the holy city were two hundred eighty-four.', pt: 'Todos os levitas na santa cidade foram duzentos e oitenta e quatro.' },
      { v: 19, en: 'Moreover the gatekeepers, Akkub, Talmon, and their brothers, who kept watch at the gates, were one hundred seventy-two.', pt: 'Também os porteiros, Acube, Talmom, e seus irmãos, os guardas das portas, foram cento e sessenta e dois.' },
      { v: 20, en: 'The residue of Israel, of the priests, the Levites, were in all the cities of Judah, everyone in his inheritance.', pt: 'O resto de Israel e dos sacerdotes e levitas, habitou em todas as cidades de Judá, cada um na sua herança.' },
      { v: 21, en: 'But the temple servants lived in Ophel: and Ziha and Gishpa were over the temple servants.', pt: 'Os netinins, porém, habitaram em Ofel; e Ziá e Gispa presidiram sobre eles.' },
      { v: 22, en: 'The overseer also of the Levites at Jerusalem was Uzzi the son of Bani, the son of Hashabiah, the son of Mattaniah, the son of Mica, of the sons of Asaph, the singers, over the business of God’s house.', pt: 'O superintendente dos levitas em Jerusalém era Uzi, filho de Bani, filho de Hasabias, filho de Matanias, filho de Mica, dos filhos de Asafe, os cantores; ele estava encarregado do serviço da casa de Deus.' },
      { v: 23, en: 'For there was a commandment from the king concerning them, and a settled provision for the singers, as every day required.', pt: 'Pois havia uma ordem da parte do rei acerca deles, e uma norma para os cantores, estabelecendo o dever de cada dia.' },
      { v: 24, en: 'Pethahiah the son of Meshezabel, of the children of Zerah the son of Judah, was at the king’s hand in all matters concerning the people.', pt: 'E Petaías, filho de Mesezabel, dos filhos de Zerá, filho de Judá, estava às ordens do rei, em todos os negócios concernentes ao povo.' },
      { v: 25, en: 'As for the villages, with their fields, some of the children of Judah lived in Kiriath Arba and its towns, in Dibon and its towns, in Jekabzeel and its villages,', pt: 'E quanto às aldeias com os seus campos, alguns dos filhos de Judá habitaram em Quiriate-Arba e seus arrabaldes, em Dibom e seus arrabaldes, e em Jecabzeel e suas aldeias;' },
      { v: 26, en: 'in Jeshua, in Moladah, Beth Pelet,', pt: 'em Jesuá, em Molada, em Bete-Pelete,' },
      { v: 27, en: 'in Hazar Shual, in Beersheba and its towns,', pt: 'Em Hazar-Sual, em Berseba e seus arrabaldes,' },
      { v: 28, en: 'in Ziklag, in Meconah and in its towns,', pt: 'em Ziclague, em Mecona e seus arrabaldes,' },
      { v: 29, en: 'in En Rimmon, in Zorah, in Jarmuth,', pt: 'em En-Rimom, em Zorá, em Jarmute,' },
      { v: 30, en: 'Zanoah, Adullam, and their villages, Lachish and its fields, and Azekah and its towns. So they encamped from Beersheba to the valley of Hinnom.', pt: 'em Zanoa, em Adulão e suas aldeias, em Laquis e seus campos, e em Azeca e seus arrabaldes. Acamparam-se, pois, desde Berseba até o vale do Hinom.' },
      { v: 31, en: 'The children of Benjamin also lived from Geba onward, at Michmash and Aija, and at Bethel and its towns,', pt: 'Os filhos de Benjamim também habitaram desde Geba em diante, em Micmás e Aíja, em Betel e seus arrabaldes,' },
      { v: 32, en: 'at Anathoth, Nob, Ananiah,', pt: 'em Anatote, em Nobe, em Ananias,' },
      { v: 33, en: 'Hazor, Ramah, Gittaim,', pt: 'em Hazor, em Ramá, em Gitaim,' },
      { v: 34, en: 'Hadid, Zeboim, Neballat,', pt: 'em Hadide, em Zeboim, em Nebalate,' },
      { v: 35, en: 'Lod, and Ono, the valley of craftsmen.', pt: 'em Lode, e em Ono, vale dos artífices.' },
      { v: 36, en: 'Of the Levites, certain divisions in Judah settled in Benjamin’s territory.', pt: 'E dos levitas que habitavam em Judá, algumas turmas foram unidas a Benjamim.' },
    ],
    12: [
      { v: 1, en: 'Now these are the priests and the Levites who went up with Zerubbabel the son of Shealtiel, and Jeshua: Seraiah, Jeremiah, Ezra,', pt: 'Ora, estes são os sacerdotes e os levitas que subiram com Zorobabel, filho de Sealtiel, e com Jesuá: Seraías, Jeremias, Esdras,' },
      { v: 2, en: 'Amariah, Malluch, Hattush,', pt: 'Amarias, Maluque, Hatus,' },
      { v: 3, en: 'Shecaniah, Rehum, Meremoth,', pt: 'Ido, Ginetói, Abias,' },
      { v: 4, en: 'Iddo, Ginnethoi, Abijah,', pt: 'Secanias, Reum, Meremote,' },
      { v: 5, en: 'Mijamin, Maadiah, Bilgah,', pt: 'Miamim, Maadias, Bilga,' },
      { v: 6, en: 'Shemaiah, and Joiarib, Jedaiah.', pt: 'Semaías, Joiaribe, Jedaías,' },
      { v: 7, en: 'Sallu, Amok, Hilkiah, and Jedaiah. These were the chiefs of the priests and of their brothers in the days of Jeshua.', pt: 'Salu, Amoque, Hilquias e Jedaías; estes foram os chefes dos sacerdotes e de seus irmãos, nos dias de Jesuá.' },
      { v: 8, en: 'Moreover the Levites: Jeshua, Binnui, Kadmiel, Sherebiah, Judah, and Mattaniah, who was over the thanksgiving, he and his brothers.', pt: 'E os levitas: Jesuá, Binuí, Cadmiel, Serebias, Judá, Matanias; este e seus irmãos dirigiam os louvores.' },
      { v: 9, en: 'Also Bakbukiah and Unno, their brothers, were close to them according to their offices.', pt: 'E Baquebuquias e Uni, seus irmãos, estavam defronte deles segundo os seus cargos.' },
      { v: 10, en: 'Jeshua became the father of Joiakim, and Joiakim became the father of Eliashib, and Eliashib became the father of Joiada,', pt: 'Jesuá foi pai de Joiaquim, Joiaquim de Eliasibe, Eliasibe de Joiada,' },
      { v: 11, en: 'and Joiada became the father of Jonathan, and Jonathan became the father of Jaddua.', pt: 'Joiada de Jonatã, e Jonatã de Jadua.' },
      { v: 12, en: 'In the days of Joiakim were priests, heads of fathers’ households: of Seraiah, Meraiah; of Jeremiah, Hananiah;', pt: 'E nos dias de Joiaquim foram sacerdotes, chefes das casas paternas: por Seraías, Meraías; por Jeremias, Hananias;' },
      { v: 13, en: 'of Ezra, Meshullam; of Amariah, Jehohanan;', pt: 'por Esdras, Mesulão; por Amarias, Jeoanã;' },
      { v: 14, en: 'of Malluchi, Jonathan; of Shebaniah, Joseph;', pt: 'por Malúqui, Jonatã; por Sebanias, José;' },
      { v: 15, en: 'of Harim, Adna; of Meraioth, Helkai;', pt: 'por Harim, Adná; por Meraiote, Helcai;' },
      { v: 16, en: 'of Iddo, Zechariah; of Ginnethon, Meshullam;', pt: 'por Ido, Zacarias; por Gineton, Mesulão;' },
      { v: 17, en: 'of Abijah, Zichri; of Miniamin, of Moadiah, Piltai;', pt: 'por Abias, Zicri; por Miniamim, por Moadias, Piltai;' },
      { v: 18, en: 'of Bilgah, Shammua; of Shemaiah, Jehonathan;', pt: 'por Bilga, Samua; por Semaías, Jeonatã;' },
      { v: 19, en: 'and of Joiarib, Mattenai; of Jedaiah, Uzzi;', pt: 'por Joiaribe, Matenai; por Jedaías, Uzi;' },
      { v: 20, en: 'of Sallai, Kallai; of Amok, Eber;', pt: 'por Salai, Calai; por Amoque, Eber;' },
      { v: 21, en: 'of Hilkiah, Hashabiah; of Jedaiah, Nethanel.', pt: 'por Hilquias, Hasabias; por Jedaías, Netanel.' },
      { v: 22, en: 'As for the Levites, in the days of Eliashib, Joiada, and Johanan, and Jaddua, there were recorded the heads of fathers’ households; also the priests, in the reign of Darius the Persian.', pt: 'Nos dias de Eliasibe, Joiada, Joanã e Jadua foram inscritos, dos levitas, os chefes das casas paternas; e assim também os dos sacerdotes, no reinado de Dário, o persa.' },
      { v: 23, en: 'The sons of Levi, heads of fathers’ households, were written in the book of the chronicles, even until the days of Johanan the son of Eliashib.', pt: 'Os filhos de Levi, chefes de casas paternas, foram inscritos no livro das crônicas, até os dias de Joanã, filho de Eliasibe.' },
      { v: 24, en: 'The chiefs of the Levites: Hashabiah, Sherebiah, and Jeshua the son of Kadmiel, with their brothers close to them, to praise and give thanks, according to the commandment of David the man of God, watch next to watch.', pt: 'Foram, pois, os chefes dos levitas: Hasabias, Serebias, Jesuá, filho de Cadmiel, e seus irmãos que ficavam defronte deles, turma contra turma, para louvarem e darem graças, segundo a ordem de Davi, homem de Deus.' },
      { v: 25, en: 'Mattaniah, and Bakbukiah, Obadiah, Meshullam, Talmon, Akkub, were gatekeepers keeping the watch at the storehouses of the gates.', pt: 'Matanias, Baquebuquias, Obadias, Mesulão, Talmom, e Acube eram porteiros, e faziam a guarda junto aos celeiros das portas.' },
      { v: 26, en: 'These were in the days of Joiakim the son of Jeshua, the son of Jozadak, and in the days of Nehemiah the governor, and of Ezra the priest and scribe.', pt: 'Estes viveram nos dias de Joiaquim, filho de Jesuá, filho de Jozadaque, como também nos dias de Neemias, o governador, e do sacerdote Esdras, o escriba.' },
      { v: 27, en: 'At the dedication of the wall of Jerusalem, they sought the Levites out of all their places, to bring them to Jerusalem, to keep the dedication with gladness, both with giving thanks, and with singing, with cymbals, stringed instruments, and with harps.', pt: 'Ora, na dedicação dos muros de Jerusalém buscaram os levitas de todos os lugares, para os trazerem a Jerusalém, a fim de celebrarem a dedicação com alegria e com ações de graças, e com canto, címbalos, alaúdes e harpas.' },
      { v: 28, en: 'The sons of the singers gathered themselves together, both out of the plain around Jerusalem and from the villages of the Netophathites;', pt: 'Ajuntaram-se os filhos dos cantores, tanto da campina dos arredores de Jerusalém, como das aldeias do netofatitas;' },
      { v: 29, en: 'also from Beth Gilgal, and out of the fields of Geba and Azmaveth: for the singers had built themselves villages around Jerusalem.', pt: 'como também de Bete-Gilgal, e dos campos de Geba e Azmavete; pois os cantores tinham edificado para si aldeias ao redor de Jerusalém.' },
      { v: 30, en: 'The priests and the Levites purified themselves; and they purified the people, and the gates, and the wall.', pt: 'E os sacerdotes e os levitas se purificaram, e purificaram o povo, as portas e o muro.' },
      { v: 31, en: 'Then I brought up the princes of Judah on the wall, and appointed two great companies who gave thanks and went in procession. One went on the right hand on the wall toward the dung gate;', pt: 'Então fiz subir os príncipes de Judá sobre o muro, e constituí duas grandes companhias para darem graças e andarem em procissão, uma das quais foi para a direita sobre o muro, em direção à porta do monturo;' },
      { v: 32, en: 'and after them went Hoshaiah, with half of the princes of Judah,', pt: 'e após ela seguiam Hosaías, e a metade dos príncipes de Judá,' },
      { v: 33, en: 'and Azariah, Ezra, and Meshullam,', pt: 'e Azarias, Esdras, Mesulão,' },
      { v: 34, en: 'Judah, Benjamin, Shemaiah, Jeremiah,', pt: 'Judá, Benjamim, Semaías, e Jeremias;' },
      { v: 35, en: 'and some of the priests’ sons with trumpets: Zechariah the son of Jonathan, the son of Shemaiah, the son of Mattaniah, the son of Micaiah, the son of Zaccur, the son of Asaph;', pt: 'e dos filhos dos sacerdotes, levando trombetas, Zacarias, filho de Jonatã, filho de Semaías, filho de Matanias, filho de Micaías, filho de Zacur, filho de Asafe.' },
      { v: 36, en: 'and his brothers, Shemaiah, Azarel, Milalai, Gilalai, Maai, Nethanel, Judah, and Hanani, with the musical instruments of David the man of God; and Ezra the scribe was before them.', pt: 'e seus irmãos, Semaías, Azarel, Milalai, Gilalai, Maai, Netanel, Judá e Hanâni, com os instrumento musicais de Davi, homem de Deus; e Esdras, o escriba, ia adiante deles.' },
      { v: 37, en: 'By the spring gate, and straight before them, they went up by the stairs of David’s city, at the ascent of the wall, above David’s house, even to the water gate eastward.', pt: 'À entrada da porta da fonte subiram diretamente as escadas da cidade de Davi onde começa a subida do muro, acima da casa de Davi, até a porta das águas a leste.' },
      { v: 38, en: 'The other company of those who gave thanks went to meet them, and I after them, with the half of the people, on the wall, above the tower of the furnaces, even to the wide wall,', pt: 'A outra companhia dos que davam graças foi para a esquerda, seguindo-os eu com a metade do povo, sobre o muro, passando pela torre dos fornos até a muralha larga,' },
      { v: 39, en: 'and above the gate of Ephraim, and by the old gate, and by the fish gate, and the tower of Hananel, and the tower of Hammeah, even to the sheep gate: and they stood still in the gate of the guard.', pt: 'e seguindo por cima da porta de Efraim, e da porta velha, e da porta dos peixes, e pela torre de Hananel, e a torre dos Cem até a porta das ovelhas; e pararam à porta da guarda.' },
      { v: 40, en: 'So the two companies of those who gave thanks in God’s house stood, and I, and the half of the rulers with me;', pt: 'Assim as duas companhias dos que davam graças pararam na casa de Deus, como também eu e a metade dos magistrados que estavam comigo,' },
      { v: 41, en: 'and the priests, Eliakim, Maaseiah, Miniamin, Micaiah, Elioenai, Zechariah, and Hananiah, with trumpets;', pt: 'e os sacerdotes Eliaquim, Maaséias, Miniamim, Micaías, Elioenai, Zacarias e Hananias, com trombetas,' },
      { v: 42, en: 'and Maaseiah, Shemaiah, Eleazar, Uzzi, Jehohanan, Malchijah, Elam, and Ezer. The singers sang loud, with Jezrahiah their overseer.', pt: 'com também Maaséias, Semaías, Eleazar, Uzi, Jeoanã, Malquias, Elão, e Ézer; e os cantores cantavam, tendo Jezraías por dirigente.' },
      { v: 43, en: 'They offered great sacrifices that day, and rejoiced; for God had made them rejoice with great joy; and the women and the children also rejoiced; so that the joy of Jerusalem was heard even far away.', pt: 'Naquele dia ofereceram grandes sacrifícios, e se alegraram, pois Deus lhes dera motivo de grande alegria; também as mulheres e as crianças se alegraram, de modo que o júbilo de Jerusalém se fez ouvir longe.' },
      { v: 44, en: 'On that day were men appointed over the rooms for the treasures, for the wave offerings, for the first fruits, and for the tithes, to gather into them, according to the fields of the cities, the portions appointed by the law for the priests and Levites; for Judah rejoiced for the priests and for the Levites who waited.', pt: 'No mesmo dia foram nomeados homens sobre as câmaras do tesouro para as ofertas alçadas, as primícias e os dízimos, para nelas recolherem, dos campos, das cidades, os quinhões designados pela lei para os sacerdotes e para os levitas; pois Judá se alegrava por estarem os sacerdotes e os levitas no seu posto,' },
      { v: 45, en: 'They performed the duty of their God, and the duty of the purification, and so did the singers and the gatekeepers, according to the commandment of David, and of Solomon his son.', pt: 'observando os preceitos do seu Deus, e os da purificação, como também o fizeram os cantores e porteiros, conforme a ordem de Davi e de seu filho Salomão.' },
      { v: 46, en: 'For in the days of David and Asaph of old there was a chief of the singers, and songs of praise and thanksgiving to God.', pt: 'Pois desde a antigüidade, já nos dias de Davi e de Asafe, havia um chefe dos cantores, e havia cânticos de louvor e de ação de graça a Deus.' },
      { v: 47, en: 'All Israel in the days of Zerubbabel, and in the days of Nehemiah, gave the portions of the singers and the gatekeepers, as every day required; and they set apart that which was for the Levites; and the Levites set apart that which was for the sons of Aaron.', pt: 'Pelo que todo o Israel, nos dias de Zorobabel e nos dias de Neemias, dava aos cantores e aos porteiros as suas porções destinadas aos levitas, e os levitas separavam as porções destinadas aos filhos de Arão.' },
    ],
    13: [
      { v: 1, en: 'On that day they read in the book of Moses in the hearing of the people; and it was found written in it that an Ammonite and a Moabite should not enter into the assembly of God forever,', pt: 'Naquele dia leu-se o livro de Moisés, na presença do povo, e achou-se escrito nele que os amonitas e os moabitas não entrassem jamais na assembléias de Deus;' },
      { v: 2, en: 'because they didn’t meet the children of Israel with bread and with water, but hired Balaam against them, to curse them; however our God turned the curse into a blessing.', pt: 'porquanto não tinham saído ao encontro dos filhos de Israel com pão e água, mas contra eles assalariaram Balaão para os amaldiçoar; contudo o nosso Deus converteu a maldição em benção.' },
      { v: 3, en: 'It came to pass, when they had heard the law, that they separated all the mixed multitude from Israel.', pt: 'Ouvindo eles esta lei, apartaram de Israel toda a multidão mista.' },
      { v: 4, en: 'Now before this, Eliashib the priest, who was appointed over the rooms of the house of our God, being allied to Tobiah,', pt: 'Ora, antes disto Eliasibe, sacerdote, encarregado das câmaras da casa de nosso Deus, se aparentara com Tobias,' },
      { v: 5, en: 'had prepared for him a great room, where before they laid the meal offerings, the frankincense, the vessels, and the tithes of the grain, the new wine, and the oil, which were given by commandment to the Levites, the singers, and the gatekeepers; and the wave offerings for the priests.', pt: 'e lhe fizera uma câmara grande, onde dantes se recolhiam as ofertas de cereais, o incenso, os utensílios, os dízimos dos cereais, do mosto e do azeite, que eram dados por ordenança aos levitas, aos cantores e aos porteiros, como também as ofertas alçadas para os sacerdotes.' },
      { v: 6, en: 'But in all this, I was not at Jerusalem; for in the thirty-second year of Artaxerxes king of Babylon I went to the king; and after some days I asked leave of the king,', pt: 'Mas durante todo este tempo não estava eu em Jerusalém, porque no ano trinta e dois de Artaxerxes, rei da Babilônia, fui ter com o rei; mas a cabo de alguns dias pedi licença ao rei,' },
      { v: 7, en: 'and I came to Jerusalem, and understood the evil that Eliashib had done for Tobiah, in preparing him a room in the courts of God’s house.', pt: 'e vim a Jerusalém; e soube do mal que Eliasibe fizera em servir a Tobias, preparando-lhe uma câmara nos átrios da casa de Deus.' },
      { v: 8, en: 'It grieved me severely. Therefore I threw all Tobiah’s household stuff out of the room.', pt: 'Isso muito me desagradou; pelo que lancei todos os móveis da casa de Tobias fora da câmara.' },
      { v: 9, en: 'Then I commanded, and they cleansed the rooms. I brought into them the vessels of God’s house, with the meal offerings and the frankincense again.', pt: 'Então, por minha ordem purificaram as câmaras; e tornei a trazer para ali os utensílios da casa de Deus, juntamente com as ofertas de cereais e o incenso.' },
      { v: 10, en: 'I perceived that the portions of the Levites had not been given them; so that the Levites and the singers, who did the work, had each fled to his field.', pt: 'Também soube que os quinhões dos levitas não se lhes davam, de maneira que os levitas e os cantores, que faziam o serviço, tinham fugido cada um para o seu campo.' },
      { v: 11, en: 'Then I contended with the rulers, and said, “Why is God’s house forsaken?” I gathered them together, and set them in their place.', pt: 'Então contendi com os magistrados e disse: Por que se abandonou a casa de Deus? Eu, pois, ajuntei os levitas e os cantores e os restaurei no seu posto.' },
      { v: 12, en: 'Then all Judah brought the tithe of the grain, the new wine, and the oil to the treasuries.', pt: 'Então todo o Judá trouxe para os celeiros os dízimos dos cereais, do mosto e do azeite.' },
      { v: 13, en: 'I made treasurers over the treasuries, Shelemiah the priest, and Zadok the scribe, and of the Levites, Pedaiah: and next to them was Hanan the son of Zaccur, the son of Mattaniah; for they were counted faithful, and their business was to distribute to their brothers.', pt: 'E por tesoureiros pus sobre os celeiros Selemias, o sacerdote, e Zadoque, o escrivão, e Pedaías, dentre os levitas, e como ajudante deles Hanã, filho de Zacur, filho de Matanias, porque foram achados fiéis; e se lhes encarregou de fazerem a distribuição entre seus irmãos.' },
      { v: 14, en: 'Remember me, my God, concerning this, and don’t wipe out my good deeds that I have done for the house of my God, and for its observances.', pt: 'Por isto, Deus meu, lembra-te de mim, e não risques as beneficências que eu tenho feito para a casa do meu Deus e para o serviço dela.' },
      { v: 15, en: 'In those days saw I in Judah some men treading wine presses on the Sabbath, bringing in sheaves, and loading donkeys; also with wine, grapes, figs, and all kinds of burdens, which they brought into Jerusalem on the Sabbath day; and I testified against them in the day in which they sold food.', pt: 'Naqueles dias vi em Judá homens que pisavam lugares no sábado, e traziam molhos, que carregavam sobre jumentos; vi também vinho, uvas e figos, e toda sorte de cargas, que eles traziam a Jerusalém no dia de sábado; e protestei contra eles quanto ao dia em que estavam vendendo mantimentos.' },
      { v: 16, en: 'Some men of Tyre also lived there, who brought in fish and all kinds of wares, and sold on the Sabbath to the children of Judah, and in Jerusalem.', pt: 'E em Jerusalém habitavam homens de Tiro, os quais traziam peixes e toda sorte de mercadorias, que vendiam no sábado aos filhos de Judá, e em Jerusalém.' },
      { v: 17, en: 'Then I contended with the nobles of Judah, and said to them, “What evil thing is this that you do, and profane the Sabbath day?', pt: 'Então contendi com os nobres de Judá, e lhes disse: Que mal é este que fazeis, profanando o dia de sábado?' },
      { v: 18, en: 'Didn’t your fathers do thus, and didn’t our God bring all this evil on us, and on this city? Yet you bring more wrath on Israel by profaning the Sabbath.”', pt: 'Porventura não fizeram vossos pais assim, e não trouxe nosso Deus todo este mal sobre nós e sobre esta cidade? Contudo vós ainda aumentais a ira sobre Israel, profanando o sábado.' },
      { v: 19, en: 'It came to pass that when the gates of Jerusalem began to be dark before the Sabbath, I commanded that the doors should be shut, and commanded that they should not be opened until after the Sabbath. I set some of my servants over the gates, so that no burden should be brought in on the Sabbath day.', pt: 'E sucedeu que, ao começar a fazer-se escuro nas portas de Jerusalém, antes do sábado, eu ordenei que elas fossem fechadas, e mandei que não as abrissem até passar o sábado e pus às portas alguns de meus moços, para que nenhuma carga entrasse no dia de sábado.' },
      { v: 20, en: 'So the merchants and sellers of all kinds of wares camped outside of Jerusalem once or twice.', pt: 'Então os negociantes e os vendedores de toda sorte de mercadorias passaram a noite fora de Jerusalém, uma ou duas vezes.' },
      { v: 21, en: 'Then I testified against them, and said to them, “Why do you stay around the wall? If you do so again, I will lay hands on you.” From that time on, they didn’t come on the Sabbath.', pt: 'Protestei, pois, contra eles, dizendo-lhes: Por que passais a noite defronte do muro? Se outra vez o fizerdes, hei de lançar mão em vós. Daquele tempo em diante não vieram no sábado.' },
      { v: 22, en: 'I commanded the Levites that they should purify themselves, and that they should come and keep the gates, to sanctify the Sabbath day. Remember to me, my God, this also, and spare me according to the greatness of your loving kindness.', pt: 'Também ordenei aos levitas que se purificassem, e viessem guardar as portas, para santificar o sábado. Nisso também, Deus meu, lembra-te de mim, e perdoa-me segundo a abundância da tua misericórdia.' },
      { v: 23, en: 'In those days I also saw the Jews who had married women of Ashdod, of Ammon, and of Moab;', pt: 'Vi também naqueles dias judeus que tinham casado com mulheres asdoditas, amonitas, e moabitas;' },
      { v: 24, en: 'and their children spoke half in the speech of Ashdod, and could not speak in the Jews’ language, but according to the language of each people.', pt: 'e seus filhos falavam no meio asdodita, e não podiam falar judaico, senão segundo a língua de seu povo.' },
      { v: 25, en: 'I contended with them, and cursed them, and struck certain of them, and plucked off their hair, and made them swear by God, “You shall not give your daughters to their sons, nor take their daughters for your sons, or for yourselves.', pt: 'Contendi com eles, e os amaldiçoei; espanquei alguns deles e, arrancando-lhes os cabelos, os fiz jurar por Deus, e lhes disse: Não darei vossas filhas a seus filhos, e não tomareis suas filhas para vossos filhos, nem para vós mesmos.' },
      { v: 26, en: 'Didn’t Solomon king of Israel sin by these things? Yet among many nations was there no king like him, and he was beloved of his God, and God made him king over all Israel. Nevertheless foreign women caused even him to sin.', pt: 'Não pecou nisso Salomão, rei de Israel? Entre muitas nações não havia rei semelhante a ele, e ele era amado de seu Deus, e Deus o constituiu rei sobre todo o Israel. Contudo mesmo a ele as mulheres estrangeiras o fizeram pecar.' },
      { v: 27, en: 'Shall we then listen to you to do all this great evil, to trespass against our God in marrying foreign women?”', pt: 'E dar-vos-íamos nós ouvidos, para fazermos todo este grande mal, esta infidelidade contra o nosso Deus, casando com mulheres estrangeiras?' },
      { v: 28, en: 'One of the sons of Joiada, the son of Eliashib the high priest, was son-in-law to Sanballat the Horonite; therefore I chased him from me.', pt: 'Também um dos filhos de Joiada, filho do sumo sacerdote Eliasibe, era genro de Sambalate, o horonita, pelo que o afugentei de mim.' },
      { v: 29, en: 'Remember them, my God, because they have defiled the priesthood, and the covenant of the priesthood and of the Levites.', pt: 'Lembra-te deles, Deus meu, pois contaminaram o sacerdocio, como tambem o pacto do sacerdocio e dos levitas.' },
      { v: 30, en: 'Thus I cleansed them from all foreigners, and appointed duties for the priests and for the Levites, everyone in his work;', pt: 'Assim os purifiquei de tudo que era estrangeiro, e determinei os cargos para os sacerdotes e para os levitas, cada um na sua função;' },
      { v: 31, en: 'and for the wood offering, at times appointed, and for the first fruits. Remember me, my God, for good.', pt: 'como também o que diz respeito à oferta da lenha em tempos determinados, e bem assim às primícias. Lembra-te de mim, Deus meu, para o meu bem.' },
    ],
  },
};

export default book;
